function getNextRailTrackName() {
  let max = -1;
  railTrackDefs.forEach((track) => {
    const match = String(track?.name || '').match(/^Points_(\d+)$/i);
    if (!match) { return; }
    const num = Number(match[1]);
    if (Number.isFinite(num)) {
      max = Math.max(max, num);
    }
  });
  return `Points_${max + 1}`;
}

function commitRailStraightDraft(endPoint) {
  if (!railStraightDraftStart?.isVector3 || !endPoint?.isVector3) { return false; }
  if (railStraightDraftStart.distanceToSquared(endPoint) < 1e-8) { return false; }
  const trackName = getNextRailTrackName();
  const points = [railStraightDraftStart.clone(), endPoint.clone()];
  const track = {
    name: trackName,
    points,
    curve: new THREE.CatmullRomCurve3(points),
  };
  railTrackDefs.push(track);
  railTrackCurveMap[trackName] = track.curve;
  railTubeDirty = true;
  structureSamplesDirty = true;
  toggleRailTube(true);
  refreshRailSelectionTargets();
  selectedRailPoint = { trackName, pointIndex: 1 };
  updateRailSelectionStatus();
  setGroupModeTrackOptions();
  setDifferenceLineOptions();
  cancelRailStraightDraft();
  hideRailInsertHoverPin();
  return true;
}

function updateRailInsertHoverFromPointer() {
  const canShow = railModeActive
    && editObject === 'RAIL'
    && objectEditMode === 'CREATE_NEW'
    && !pointerBlockedByUI;
  if (!canShow || !railTubeMesh?.parent) {
    hideRailInsertHoverPin();
    return;
  }
  raycaster.setFromCamera(mouse, camera);
  const hit = raycaster.intersectObject(railTubeMesh, true)[0] || null;
  if (!hit?.point) {
    hideRailInsertHoverPin();
    return;
  }
  const hitTrack = resolveRailTrackByTubeHit(hit);
  const nearestTrackHit = hitTrack
    ? getNearestPointOnRailTrackCurve(hitTrack, hit.point, 700)
    : getNearestRailTrackHitFromPoint(hit.point, 700);
  if (!nearestTrackHit?.trackName || !nearestTrackHit?.point) {
    hideRailInsertHoverPin();
    return;
  }
  railInsertHoverHit = nearestTrackHit;
  ensureRailInsertHoverPin();
  railInsertHoverPin.position.copy(nearestTrackHit.point);
  railInsertHoverPin.visible = true;
}

function getNearestRailTrackHitFromPoint(worldPoint, resolution = 600) {
  if (!worldPoint) { return null; }
  let best = null;
  let bestDistSq = Infinity;
  const sample = new THREE.Vector3();
  railTrackDefs.forEach((track) => {
    const curve = track?.curve;
    if (!curve || typeof curve.getPointAt !== 'function') { return; }
    for (let i = 0; i <= resolution; i += 1) {
      const t = i / resolution;
      sample.copy(curve.getPointAt(t));
      const distSq = sample.distanceToSquared(worldPoint);
      if (distSq < bestDistSq) {
        bestDistSq = distSq;
        best = {
          trackName: track.name,
          t,
          point: sample.clone(),
          distSq,
        };
      }
    }
  });
  return best;
}

function getNearestPointOnRailTrackCurve(track, worldPoint, resolution = 700) {
  if (!track?.curve || typeof track.curve.getPointAt !== 'function' || !worldPoint) { return null; }
  let best = null;
  let bestDistSq = Infinity;
  const sample = new THREE.Vector3();
  for (let i = 0; i <= resolution; i += 1) {
    const t = i / resolution;
    sample.copy(track.curve.getPointAt(t));
    const distSq = sample.distanceToSquared(worldPoint);
    if (distSq < bestDistSq) {
      bestDistSq = distSq;
      best = {
        trackName: track.name,
        t,
        point: sample.clone(),
        distSq,
      };
    }
  }
  return best;
}

function resolveRailTrackByTubeHit(hit) {
  const materialIndexRaw = hit?.face?.materialIndex;
  const materialIndex = Number.isInteger(materialIndexRaw)
    ? materialIndexRaw
    : Number(materialIndexRaw);
  if (!Number.isFinite(materialIndex)) { return null; }
  const idx = Math.max(0, Math.floor(materialIndex));
  return railTrackDefs[idx] || null;
}

function isRailPointPickMesh(mesh) {
  return Boolean(
    mesh?.userData
    && mesh.userData.trackName != null
    && mesh.userData.pointIndex != null
  );
}

function pickRailMoveTargetFromPointer({ allowRailPoint = true } = {}) {
  raycaster.setFromCamera(mouse, camera);
  const intersects = raycaster.intersectObjects(targetObjects, true);
  if (!Array.isArray(intersects) || intersects.length < 1) { return null; }
  if (allowRailPoint) {
    const pointHit = intersects.find((hit) => {
      const obj = resolveSelectableHitObject(hit?.object || null);
      return isRailPointPickMesh(obj);
    }) || null;
    if (pointHit) {
      return resolveSelectableHitObject(pointHit.object);
    }
  }
  const handleHit = intersects.find((hit) => {
    const obj = resolveSelectableHitObject(hit?.object || null);
    return Boolean(obj?.userData?.railStructureHandle && obj?.userData?.railStructurePickHandle);
  }) || null;
  if (handleHit) {
    return resolveSelectableHitObject(handleHit.object);
  }
  return resolveSelectableHitObject(intersects[0].object);
}

function getInsertIndexOnTrackPoints(points, worldPoint) {
  if (!Array.isArray(points) || points.length < 2 || !worldPoint) { return null; }
  let bestSeg = 0;
  let bestDistSq = Infinity;
  const line = new THREE.Line3();
  const nearest = new THREE.Vector3();
  for (let i = 0; i < points.length - 1; i += 1) {
    const a = points[i];
    const b = points[i + 1];
    if (!a || !b) { continue; }
    line.set(a, b);
    line.closestPointToPoint(worldPoint, true, nearest);
    const distSq = nearest.distanceToSquared(worldPoint);
    if (distSq < bestDistSq) {
      bestDistSq = distSq;
      bestSeg = i;
    }
  }
  // 区間への挿入なので基本は i と i+1 の間に入れる。
  return Math.max(1, Math.min(points.length - 1, bestSeg + 1));
}

function insertRailControlPointFromPointer() {
  if (!railModeActive || !railTubeMesh?.parent) { return false; }
  let nearestTrackHit = railInsertHoverHit;
  if (!nearestTrackHit?.trackName || !nearestTrackHit?.point) {
    raycaster.setFromCamera(mouse, camera);
    const hit = raycaster.intersectObject(railTubeMesh, true)[0] || null;
    if (!hit?.point) { return false; }
    const hitTrack = resolveRailTrackByTubeHit(hit);
    nearestTrackHit = hitTrack
      ? getNearestPointOnRailTrackCurve(hitTrack, hit.point, 700)
      : getNearestRailTrackHitFromPoint(hit.point, 700);
  }
  if (!nearestTrackHit?.trackName || !nearestTrackHit?.point) { return false; }
  const track = getRailTrackByName(nearestTrackHit.trackName);
  if (!track?.points || track.points.length < 2) { return false; }
  const insertIndex = getInsertIndexOnTrackPoints(track.points, nearestTrackHit.point);
  if (!Number.isInteger(insertIndex)) { return false; }

  const insertedPoint = nearestTrackHit.point.clone();
  track.points.splice(insertIndex, 0, insertedPoint);
  if (track.curve) {
    track.curve.points = track.points;
    track.curve.cacheArcLengths = null;
    track.curve.needsUpdate = true;
    if (typeof track.curve.updateArcLengths === 'function') {
      track.curve.updateArcLengths();
    }
    if (railTrackCurveMap && typeof track.name === 'string') {
      railTrackCurveMap[track.name] = track.curve;
    }
  }

  railTubeDirty = true;
  structureSamplesDirty = true;
  refreshRailSelectionTargets();
  setMeshListOpacity(targetObjects, 1);
  selectedRailPoint = { trackName: track.name, pointIndex: insertIndex };
  drawRailSelectionLine(track.name, insertIndex);
  const selectedMesh = targetObjects.find((mesh) =>
    mesh?.userData?.trackName === track.name && mesh?.userData?.pointIndex === insertIndex
  ) || null;
  if (selectedMesh?.material?.color?.set) {
    selectedMesh.material.color.set(0x00ff00);
    choice_object = selectedMesh;
  }
  updateRailInsertHoverFromPointer();
  return true;
}

function refreshRailSelectionTargets() {
  clearRailSelectionTargetsOnly();
  targetObjects = [];
  selectedRailPoint = null;
  clearRailSelectionLine();

  const useStructureHandles = editObject === 'RAIL'
    && (objectEditMode === 'MOVE_EXISTING' || objectEditMode === ROTATE_MODE);
  if (useStructureHandles) {
    railStructurePickMeshes = [];
    const groups = collectRailStructureGroups();
    groups.forEach((entry) => {
      const bounds = new THREE.Box3();
      entry.members.forEach((member) => {
        if (!member?.parent) { return; }
        bounds.expandByObject(member);
      });
      const boundsCenter = (!bounds.isEmpty())
        ? bounds.getCenter(new THREE.Vector3())
        : entry.center.clone();
      const boundsSize = (!bounds.isEmpty())
        ? bounds.getSize(new THREE.Vector3())
        : new THREE.Vector3(1, 1, 1);
      const sx = Math.max(1.4, boundsSize.x + 0.6);
      const sy = Math.max(1.2, boundsSize.y + 0.6);
      const sz = Math.max(1.4, boundsSize.z + 0.6);
      const footprint = Math.max(sx, sz);
      const handleMaterial = new THREE.MeshStandardMaterial({
        color: 0x12b6ff,
        emissive: 0x0a4f76,
        emissiveIntensity: 0.9,
        transparent: true,
        opacity: 0.45,
        depthTest: false,
        depthWrite: false,
        wireframe: true,
      });
      const mesh = new THREE.Mesh(new THREE.BoxGeometry(1, 1, 1), handleMaterial);
      mesh.position.copy(boundsCenter);
      mesh.scale.set(footprint, sy, footprint);
      mesh.renderOrder = 9000;
      mesh.visible = true;
      mesh.userData = {
        ...(mesh.userData || {}),
        railStructureHandle: true,
        railStructurePickHandle: true,
        railStructureGroupKey: entry.key,
      };
      scene.add(mesh);
      targetObjects.push(mesh);
      railStructurePickMeshes.push(mesh);
    });
  }
  if (!useStructureHandles) {
    railStructurePickMeshes = [];
  }

  railTrackDefs.forEach((track) => {
    track.points.forEach((point, index) => {
      if (!point) { return; }
      const mesh = new THREE.Mesh(cube_geometry, cube_material.clone());
      mesh.position.copy(point);
      mesh.userData = { trackName: track.name, pointIndex: index };
      scene.add(mesh);
      targetObjects.push(mesh);
    });
  });
  updateRailSelectionStatus();
}

function applyRailStructureGroupYawDelta(groupKey, deltaDeg) {
  const key = String(groupKey || '').trim();
  const delta = Number(deltaDeg);
  if (!key || !Number.isFinite(delta) || Math.abs(delta) < 1e-8) { return false; }
  const group = collectRailStructureGroups().find((entry) => entry.key === key) || null;
  if (!group || !Array.isArray(group.members) || group.members.length < 1) { return false; }
  const rad = THREE.MathUtils.degToRad(delta);
  const quat = new THREE.Quaternion().setFromAxisAngle(new THREE.Vector3(0, 1, 0), rad);
  const center = group.center.clone();
  group.members.forEach((mesh) => {
    if (!mesh?.parent) { return; }
    if (mesh?.position?.isVector3) {
      const offset = mesh.position.clone().sub(center).applyQuaternion(quat);
      mesh.position.copy(center.clone().add(offset));
    }
    if (mesh?.quaternion?.isQuaternion) {
      mesh.quaternion.premultiply(quat);
    }
  });
  return true;
}

function clearRailSelectionTargetsOnly() {
  for (let i = targetObjects.length - 1; i >= 0; i -= 1) {
    const mesh = targetObjects[i];
    if (!mesh?.isMesh) { continue; }
    const isRailPointTarget = mesh?.userData
      && mesh.userData.trackName != null
      && mesh.userData.pointIndex != null;
    const isRailStructureHandle = Boolean(mesh?.userData?.railStructureHandle && mesh?.userData?.railStructurePickHandle);
    if (!isRailPointTarget && !isRailStructureHandle) { continue; }
    if (mesh.parent) {
      mesh.parent.remove(mesh);
    }
    if (mesh.geometry && typeof mesh.geometry.dispose === 'function') {
      mesh.geometry.dispose();
    }
    if (Array.isArray(mesh.material)) {
      mesh.material.forEach((mat) => mat?.dispose?.());
    } else {
      mesh.material?.dispose?.();
    }
    targetObjects.splice(i, 1);
  }
}

function showRailGeneratedStructures() {
  const structures = getConstructionCopyTargets().filter((mesh) => mesh?.parent);
  structures.forEach((mesh) => {
    mesh.visible = true;
    if (mesh?.userData?.steelFrameCopiedObject) {
      setCopyObjectVisual(mesh, false);
    }
    if (Array.isArray(mesh.material)) {
      mesh.material.forEach((mat) => {
        if (!mat) { return; }
        if ('opacity' in mat) { mat.opacity = 1; }
        mat.transparent = false;
      });
    } else if (mesh.material) {
      if ('opacity' in mesh.material) { mesh.material.opacity = 1; }
      mesh.material.transparent = false;
    }
  });
}

function collectRailStructureGroups() {
  const targets = getConstructionCopyTargets()
    .filter((obj) => obj?.parent)
    .filter((obj) => !obj?.userData?.steelFramePoint);
  const segmentTargets = targets.filter((mesh) => mesh?.name === 'SteelFrameSegment');
  const parentBySegId = new Map();
  const findSeg = (id) => {
    const current = parentBySegId.get(id);
    if (current == null || current === id) {
      parentBySegId.set(id, id);
      return id;
    }
    const root = findSeg(current);
    parentBySegId.set(id, root);
    return root;
  };
  const unionSeg = (aId, bId) => {
    const ra = findSeg(aId);
    const rb = findSeg(bId);
    if (ra === rb) { return; }
    if (ra < rb) {
      parentBySegId.set(rb, ra);
    } else {
      parentBySegId.set(ra, rb);
    }
  };
  segmentTargets.forEach((seg) => {
    parentBySegId.set(seg.id, seg.id);
  });

  const pointToSegIds = new Map();
  segmentTargets.forEach((seg) => {
    const refs = getCopyStructurePointMeshes(seg);
    refs.forEach((pointMesh) => {
      if (!pointMesh?.parent) { return; }
      const pointId = Number(pointMesh.id);
      if (!Number.isFinite(pointId)) { return; }
      if (!pointToSegIds.has(pointId)) {
        pointToSegIds.set(pointId, []);
      }
      pointToSegIds.get(pointId).push(seg.id);
    });
  });
  pointToSegIds.forEach((segIds) => {
    if (!Array.isArray(segIds) || segIds.length < 2) { return; }
    const first = segIds[0];
    for (let i = 1; i < segIds.length; i += 1) {
      unionSeg(first, segIds[i]);
    }
  });

  const segComponentKeyById = new Map();
  segmentTargets.forEach((seg) => {
    const root = findSeg(seg.id);
    segComponentKeyById.set(seg.id, `seg_component_${root}`);
  });

  const groupMap = new Map();
  const ensureGroup = (key, groupId = null) => {
    if (!groupMap.has(key)) {
      groupMap.set(key, {
        key,
        groupId: groupId || null,
        members: [],
      });
    }
    return groupMap.get(key);
  };
  targets.forEach((mesh) => {
    const railPlacementGroupId = String(mesh?.userData?.railPlacementGroupId || '').trim();
    const structureGroupId = String(mesh?.userData?.structureGroupId || '').trim();
    const copyGroupId = String(mesh?.userData?.steelFrameCopyGroupId || '').trim();
    const segComponentKey = mesh?.name === 'SteelFrameSegment'
      ? (segComponentKeyById.get(mesh.id) || null)
      : null;
    const key = railPlacementGroupId
      ? `rail:${railPlacementGroupId}`
      : structureGroupId
      ? `gid:${structureGroupId}`
      : (copyGroupId
        ? `copy:${copyGroupId}`
        : (segComponentKey || `single_${mesh.id}`));
    ensureGroup(key, structureGroupId || null).members.push(mesh);
  });

  // 装飾で groupId が無い場合、近傍セグメントのリンクグループへ寄せる。
  const segmentAnchors = segmentTargets.map((seg) => {
    const info = getStructureAnchorInfo(seg);
    return info ? { seg, anchor: info.anchor } : null;
  }).filter(Boolean);
  const relinkDistanceSq = 0.7 * 0.7;
  targets.forEach((mesh) => {
    if (mesh?.name === 'SteelFrameSegment') { return; }
    const gid = String(mesh?.userData?.structureGroupId || '').trim();
    const cgid = String(mesh?.userData?.steelFrameCopyGroupId || '').trim();
    if (gid || cgid) { return; }
    const decoAnchor = getStructureAnchorInfo(mesh)?.anchor || null;
    if (!decoAnchor) { return; }
    let nearestSeg = null;
    let bestDistSq = Infinity;
    segmentAnchors.forEach((entry) => {
      const d = entry.anchor.distanceToSquared(decoAnchor);
      if (d < bestDistSq) {
        bestDistSq = d;
        nearestSeg = entry.seg;
      }
    });
    if (!nearestSeg || bestDistSq > relinkDistanceSq) { return; }
    const segKey = segComponentKeyById.get(nearestSeg.id);
    if (!segKey) { return; }
    // 現在所属(single_xxx)から外してセグメント系グループへ移す。
    const currentKey = `single_${mesh.id}`;
    const currentGroup = groupMap.get(currentKey);
    if (currentGroup) {
      currentGroup.members = currentGroup.members.filter((m) => m?.id !== mesh.id);
      if (currentGroup.members.length < 1) {
        groupMap.delete(currentKey);
      }
    }
    ensureGroup(segKey, null).members.push(mesh);
  });

  const out = [];
  groupMap.forEach((group) => {
    const anchors = group.members
      .map((mesh) => getStructureAnchorInfo(mesh))
      .filter(Boolean);
    if (anchors.length < 1) { return; }
    const center = anchors
      .reduce((acc, entry) => acc.add(entry.anchor), new THREE.Vector3())
      .multiplyScalar(1 / anchors.length);
    out.push({
      ...group,
      center,
      anchors,
    });
  });
  return out;
}

function beginRailStructureGroupDrag(handleMesh) {
  railGroupDragState = null;
  const resolvedHandle = resolveRailStructurePickHandleFromObject(handleMesh) || handleMesh;
  if (!resolvedHandle?.userData?.railStructureHandle) {
    railGroupDragState = null;
    return false;
  }
  const groupKey = String(resolvedHandle?.userData?.railStructureGroupKey || '').trim();
  if (!groupKey) {
    railGroupDragState = null;
    return false;
  }
  const group = collectRailStructureGroups().find((entry) => entry.key === groupKey) || null;
  if (!group || !Array.isArray(group.members) || group.members.length < 1) {
    railGroupDragState = null;
    return false;
  }
  const members = group.members.map((mesh) => {
    const anchorInfo = getStructureAnchorInfo(mesh);
    if (!anchorInfo) { return null; }
    return {
      mesh,
      startPos: mesh.position.clone(),
      startQuat: mesh?.quaternion?.clone ? mesh.quaternion.clone() : null,
      startAnchor: anchorInfo.anchor.clone(),
    };
  }).filter(Boolean);
  if (members.length < 1) {
    railGroupDragState = null;
    return false;
  }

  // ドラッグ基準はアンカー平均ではなく、選択ボックス中心に統一する。
  // 再ドラッグ時の中心ずれで移動量が膨らむのを防ぐ。
  const dragCenter = resolvedHandle?.position?.clone?.() || group.center.clone();
  const leaderNearest = getNearestRailTrackHitFromPoint(dragCenter, 900);
  const leaderTrack = leaderNearest?.trackName ? getRailTrackByName(leaderNearest.trackName) : null;
  let leaderStartYaw = 0;
  if (leaderTrack?.curve && Number.isFinite(leaderNearest?.t) && typeof leaderTrack.curve.getTangentAt === 'function') {
    const tangent = leaderTrack.curve.getTangentAt(THREE.MathUtils.clamp(leaderNearest.t, 0, 1)).clone().setY(0);
    if (tangent.lengthSq() > 1e-8) {
      tangent.normalize();
      leaderStartYaw = Math.atan2(tangent.x, tangent.z);
    }
  }
  railGroupDragState = {
    groupKey,
    handleMesh: resolvedHandle,
    leaderTrack,
    leaderStartPoint: leaderNearest?.point?.clone?.() || dragCenter.clone(),
    leaderStartT: Number.isFinite(leaderNearest?.t) ? leaderNearest.t : 0,
    leaderStartYaw,
    centerStart: dragCenter.clone(),
    members,
  };
  return true;
}

function buildStructureSamplePoints() {
  structureSamplePoints = [];
  railTrackDefs.forEach((track) => {
    const sampled = TSys.getPointsEveryM(track.curve, structureSampleInterval);
    sampled.forEach((point) => {
      structureSamplePoints.push({ trackName: track.name, point });
    });
  });
  structureSamplesDirty = false;
}

function getNearestStructureTrackName(position) {
  if (!position) { return null; }
  if (structureSamplesDirty || structureSamplePoints.length === 0) {
    buildStructureSamplePoints();
  }
  let bestName = null;
  let bestDist = Infinity;
  for (let i = 0; i < structureSamplePoints.length; i++) {
    const sample = structureSamplePoints[i];
    const dist = sample.point.distanceToSquared(position);
    if (dist < bestDist) {
      bestDist = dist;
      bestName = sample.trackName ?? null;
    }
  }
  return bestName;
}

function ensureStructureHoverPin() {
  if (structureHoverPin) { return; }
  structureHoverPin = TSys.Map_pin(0, 0, 0, 0.15, structureHoverColor);
  structureHoverPin.name = 'StructureHoverPin';
}

function updateStructureHover() {
  if (!structureModeActive || !lastPointerScreen || structurePointerBlockedByUI) {
    if (structureHoverPin) {
      structureHoverPin.visible = false;
    }
    structureHoverPoint = null;
    structureHoverTrackName = null;
    return;
  }

  if (structureSamplesDirty || structureSamplePoints.length === 0) {
    buildStructureSamplePoints();
  }

  const rect = canvas.getBoundingClientRect();
  const w = rect.width;
  const h = rect.height;
  if (w === 0 || h === 0) { return; }

  const targetX = lastPointerScreen.x;
  const targetY = lastPointerScreen.y;

  let best = null;
  let bestDist = Infinity;
  const tmp = new THREE.Vector3();

  structureSamplePoints.forEach((sample) => {
    tmp.copy(sample.point).project(camera);
    if (tmp.z < -1 || tmp.z > 1) { return; }
    const sx = (tmp.x + 1) * 0.5 * w;
    const sy = (1 - (tmp.y + 1) * 0.5) * h;
    const dx = sx - targetX;
    const dy = sy - targetY;
    const dist = dx * dx + dy * dy;
    if (dist < bestDist) {
      bestDist = dist;
      best = sample;
    }
  });

  if (!best) {
    if (structureHoverPin) {
      structureHoverPin.visible = false;
    }
    structureHoverPoint = null;
    structureHoverTrackName = null;
    return;
  }

  structureHoverPoint = best.point.clone();
  structureHoverTrackName = best.trackName ?? null;
  ensureStructureHoverPin();
  structureHoverPin.position.copy(best.point);
  structureHoverPin.visible = true;
}

function placeStructurePinnedPin() {
  if (!structureHoverPoint) { return; }
  placeStructurePinnedPinAt(structureHoverPoint, structureHoverTrackName);
}

function placeStructurePinnedPinAt(position, trackName = null) {
  if (!position) { return; }
  const pos = position instanceof THREE.Vector3
    ? position
    : new THREE.Vector3(position.x, position.y, position.z);
  const resolvedTrackName = trackName ?? getNearestStructureTrackName(pos);
  const pin = TSys.Map_pin(
    pos.x,
    pos.z,
    pos.y,
    0.2,
    structurePinnedColor
  );
  pin.name = 'StructurePinnedPin';
  const linkedIdsRaw = Array.isArray(position?.linkedStructureObjectIds)
    ? position.linkedStructureObjectIds
    : [];
  const linkedIds = linkedIdsRaw
    .map((v) => String(v || '').trim())
    .filter((v) => v.length > 0);
  pin.userData = {
    ...pin.userData,
    constructionSelected: false,
    trackName: resolvedTrackName,
    linkedStructureObjectIds: Array.from(new Set(linkedIds)),
    structureLinkedRestored: false,
  };
  pin.visible = structureViewActive || structureModeActive || constructionModeActive;
  structurePinnedPins.push(pin);
  return pin;
}

function clearStructurePinnedPins() {
  clearConstructionSelection();
  for (let i = structurePinnedPins.length - 1; i >= 0; i--) {
    const pin = structurePinnedPins[i];
    if (pin && pin.parent) {
      pin.parent.remove(pin);
    }
    if (pin && pin.geometry && typeof pin.geometry.dispose === 'function') {
      pin.geometry.dispose();
    }
    if (pin && pin.material && typeof pin.material.dispose === 'function') {
      pin.material.dispose();
    }
    structurePinnedPins.splice(i, 1);
  }
}

function setStructurePinnedVisibility(visible) {
  structurePinnedPins.forEach((pin) => {
    if (pin) {
      pin.visible = visible;
    }
  });
}

function updateStructurePinnedVisibility() {
  setStructurePinnedVisibility(structureViewActive || structureModeActive || constructionModeActive);
}

function setPinColor(pin, color) {
  if (!pin || !pin.material) { return; }
  if (Array.isArray(pin.material)) {
    pin.material.forEach((material) => material?.color?.set?.(color));
    return;
  }
  pin.material.color?.set?.(color);
}

function isConstructionPinSelected(pin) {
  return Boolean(pin?.userData?.constructionSelected);
}

function setConstructionPinSelected(pin, selected) {
  if (!pin) { return; }
  pin.userData = pin.userData || {};
  pin.userData.constructionSelected = selected;
  setPinColor(pin, selected ? structureSelectedColor : structurePinnedColor);
}

function clearConstructionSelection() {
  constructionSelectedPins.forEach((pin) => {
    setConstructionPinSelected(pin, false);
  });
  constructionSelectedPins.length = 0;
}

function toggleConstructionPinSelection(pin) {
  if (!pin) { return; }
  if (isConstructionPinSelected(pin)) {
    setConstructionPinSelected(pin, false);
    const index = constructionSelectedPins.indexOf(pin);
    if (index !== -1) {
      constructionSelectedPins.splice(index, 1);
    }
    return;
  }
  setConstructionPinSelected(pin, true);
  constructionSelectedPins.push(pin);
}

function pickStructurePinnedPin() {
  if (structurePinnedPins.length === 0) { return null; }
  raycaster.setFromCamera(mouse, camera);
  const hits = raycaster.intersectObjects(structurePinnedPins, false);
  if (hits.length === 0) { return null; }
  return hits[0].object;
}

function getSelectedTrackCurvesForConstructionFromPinsPayload(pinsPayload) {
  const pinGroups = new Map();
  normalizePinsPayload(pinsPayload).forEach((pin) => {
    const trackName = pin.trackName;
    if (typeof trackName !== 'string' || trackName.length === 0) { return; }
    if (!pinGroups.has(trackName)) {
      pinGroups.set(trackName, []);
    }
    pinGroups.get(trackName).push(new THREE.Vector3(pin.x, pin.y, pin.z));
  });

  const getNearestTOnCurve = (curve, point, resolution = 500) => {
    let bestT = 0;
    let bestDist = Infinity;
    const sample = new THREE.Vector3();
    for (let i = 0; i <= resolution; i++) {
      const t = i / resolution;
      sample.copy(curve.getPointAt(t));
      const dist = sample.distanceToSquared(point);
      if (dist < bestDist) {
        bestDist = dist;
        bestT = t;
      }
    }
    return bestT;
  };

  const result = [];
  pinGroups.forEach((pins, trackName) => {
    const baseCurve = railTrackCurveMap[trackName];
    if (!baseCurve) { return; }
    if (pins.length < 2) {
      result.push({ trackName, curve: baseCurve.clone() });
      return;
    }
    const sortedByT = pins
      .map((point) => ({ point, t: getNearestTOnCurve(baseCurve, point) }))
      .sort((a, b) => a.t - b.t);
    const start = sortedByT[0].point;
    const end = sortedByT[sortedByT.length - 1].point;
    const segmentCurve = findCurveRange(baseCurve, start, end);
    result.push({ trackName, curve: segmentCurve });
  });

  return result;
}

function getSelectedTrackCurvesForConstruction() {
  return getSelectedTrackCurvesForConstructionFromPinsPayload(getConstructionPinsPayload());
}

function getOrderedTracksByLateralPosition(trackCurves, sampleDistance = 0.5) {
  if (!Array.isArray(trackCurves) || trackCurves.length === 0) {
    return [];
  }
  const ref = trackCurves[0];
  const refStart = ref.curve.getPointAt(0).clone();
  const refLength = ref.curve.getLength();
  const refSampleT = refLength > 0 ? Math.min(sampleDistance / refLength, 1) : 0;
  const refEnd = ref.curve.getPointAt(refSampleT).clone();
  const refDir = refEnd.sub(refStart).setY(0);
  if (refDir.lengthSq() === 0) {
    refDir.set(0, 0, 1);
  } else {
    refDir.normalize();
  }
  const refAngle = Math.atan2(refDir.x, refDir.z);
  const normalizeRadSigned = (rad) => {
    let value = rad;
    while (value > Math.PI) { value -= Math.PI * 2; }
    while (value < -Math.PI) { value += Math.PI * 2; }
    return value;
  };

  return trackCurves.map((entry) => {
    let workingCurve = entry.curve.clone();
    const rawStart = workingCurve.getPointAt(0).clone();
    const rawEnd = workingCurve.getPointAt(1).clone();
    const dirB = rawEnd.clone().sub(rawStart).setY(0);
    if (dirB.lengthSq() === 0) {
      dirB.copy(refDir);
    } else {
      dirB.normalize();
    }
    const dot = Math.min(1, Math.max(-1, refDir.dot(dirB)));
    const angleBetween = Math.acos(dot);
    let reversed = false;
    if (angleBetween >= Math.PI * 0.5 && entry.trackName !== ref.trackName) {
      reversed = true;
      const reversedPoints = workingCurve.getPoints(300).map((point) => point.clone()).reverse();
      workingCurve = new THREE.CatmullRomCurve3(reversedPoints);
    }
    const point = workingCurve.getPointAt(0).clone();
    const vec = point.sub(refStart).setY(0);
    const distance = vec.length();
    const vecNorm = distance > 0 ? vec.clone().multiplyScalar(1 / distance) : new THREE.Vector3(0, 0, 1);
    const angle = Math.atan2(vecNorm.x, vecNorm.z);
    const delta = normalizeRadSigned(angle - refAngle);
    const xLocal = Math.sin(delta) * distance;
    return {
      trackName: entry.trackName,
      xLocal,
      delta,
      distance,
      reversed,
      curve: workingCurve,
      refTrackName: ref.trackName,
    };
  }).sort((a, b) => b.xLocal - a.xLocal);
}

function getEdgeTrackNamesForConstruction(sampleDistance = 0.5) {
  const trackCurves = getSelectedTrackCurvesForConstruction();
  const ordered = getOrderedTracksByLateralPosition(trackCurves, sampleDistance);
  if (ordered.length === 0) {
    return { right: null, left: null, ordered: [] };
  }
  return {
    right: ordered[0].trackName,
    left: ordered[ordered.length - 1].trackName,
    ordered,
  };
}

function getEdgeTrackNamesForConstructionFromPinsPayload(pinsPayload, sampleDistance = 0.5) {
  const trackCurves = getSelectedTrackCurvesForConstructionFromPinsPayload(pinsPayload);
  const ordered = getOrderedTracksByLateralPosition(trackCurves, sampleDistance);
  if (ordered.length === 0) {
    return { right: null, left: null, ordered: [] };
  }
  return {
    right: ordered[0].trackName,
    left: ordered[ordered.length - 1].trackName,
    ordered,
  };
}

function logPillarSideJudgement() {
  const trackCurves = getSelectedTrackCurvesForConstruction();
  if (trackCurves.length < 2) {
    console.warn('pillar judgement requires at least 2 selected tracks.');
    return;
  }
  const rows = [];
  for (let i = 0; i < trackCurves.length; i++) {
    for (let j = i + 1; j < trackCurves.length; j++) {
      const a = trackCurves[i];
      const b = trackCurves[j];
      const side = TSys.getCurveSideByDirection(a.curve, b.curve, 0.5);
      rows.push({
        leftTrack: a.trackName,
        rightTrack: b.trackName,
        side,
      });
    }
  }
  const order = { right: 0, center: 1, left: 2 };
  rows.sort((r1, r2) => {
    const v1 = order[r1.side] ?? 99;
    const v2 = order[r2.side] ?? 99;
    if (v1 !== v2) { return v1 - v2; }
    return `${r1.leftTrack}->${r1.rightTrack}`.localeCompare(`${r2.leftTrack}->${r2.rightTrack}`);
  });
  rows.forEach((row) => {
  });

  const scored = getOrderedTracksByLateralPosition(trackCurves, 0.5);
  const reversedTracks = scored.filter((row) => row.reversed).map((row) => row.trackName);
  if (reversedTracks.length > 0) {
  } else {
  }
  if (scored.length > 0) {
    const rightmost = scored[0].trackName;
    const leftmost = scored[scored.length - 1].trackName;
  }
}

async function loadStructureData(url) {
  try {
    const response = await fetch(url, { cache: 'no-store' });
    if (!response.ok) {
      return;
    }
    const data = await response.json();
    applyStructureDataPayload(data);
  } catch (err) {
    console.warn('structure.json load failed', err);
  }
}

function applyStructureDataPayload(data) {
  if (!data || typeof data !== 'object' || !Array.isArray(data.pins)) {
    console.info('[public_upload][pins] skipped invalid structure payload', {
      hasData: Boolean(data),
      hasPins: Array.isArray(data?.pins),
    });
    return false;
  }
  clearStructurePinnedPins();
  const loadedRuns = Array.isArray(data.generationRuns)
    ? data.generationRuns.map((run) => ({
      category: String(run?.category || '').trim(),
      pins: normalizePinsPayload(run?.pins),
      params: (run?.params && typeof run.params === 'object') ? { ...run.params } : {},
    })).filter((run) => run.category && run.pins.length > 0)
    : [];
  structureGenerationRuns = dedupeGenerationRuns(loadedRuns).map((run) => ({
    ...run,
    replayDone: false,
  }));
  console.info('[public_upload][pins] restoring structure payload', {
    pinCount: data.pins.length,
    generationRunCount: structureGenerationRuns.length,
    generationRunCategories: structureGenerationRuns.map((run) => String(run?.category || '').trim()),
  });
  data.pins.forEach((pin) => {
    if (!pin || !Number.isFinite(pin.x) || !Number.isFinite(pin.y) || !Number.isFinite(pin.z)) {
      console.info('[public_upload][pins] skipped invalid pin', pin);
      return;
    }
    console.info('[public_upload][pins] place pin', {
      x: pin.x,
      y: pin.y,
      z: pin.z,
      trackName: pin.trackName ?? null,
      linkedStructureObjectIds: Array.isArray(pin?.linkedStructureObjectIds) ? pin.linkedStructureObjectIds.length : 0,
    });
    placeStructurePinnedPinAt(pin, pin.trackName ?? null);
  });
  if (data.pins.length > 0) {
    structureViewActive = true;
  }
  updateStructurePinnedVisibility();
  structureGenerationReplayPending = structureGenerationRuns.length > 0;
  if (structureGenerationReplayPending) {
    console.info('[public_upload][pins] schedule generation replay', {
      generationRunCount: structureGenerationRuns.length,
    });
    scheduleReplayStructureGenerationRuns({ resetRetry: true });
  } else {
    console.info('[public_upload][pins] no generation replay, rebuild linked objects only');
    scheduleRebuildStructureLinkedObjects({ resetRetry: true });
  }
  return true;
}

function replayStructureGenerationRunsFromStructureData() {
  if (!structureGenerationReplayPending) { return true; }
  if (!structureLinkRuntimeReady) {
    console.info('[public_upload][pins] replay deferred: structureLinkRuntimeReady=false', {
      retryCount: structureGenerationReplayRetryCount,
    });
    if (structureGenerationReplayRetryCount < STRUCTURE_GENERATION_REPLAY_MAX_RETRY) {
      structureGenerationReplayRetryCount += 1;
      scheduleReplayStructureGenerationRuns();
    }
    return false;
  }
  if (structureGenerationReplayActive) { return; }
  structureGenerationReplayActive = true;
  try {
    let unresolvedGroupReference = false;
    let pendingRunCount = 0;
    structureGenerationRuns.forEach((run) => {
      if (run?.replayDone) { return; }
      const kind = String(run?.category || '').trim();
      if (!kind) { return; }
      const pins = normalizePinsPayload(run?.pins);
      if (pins.length < 1) { return; }
      pendingRunCount += 1;
      const params = (run?.params && typeof run.params === 'object') ? run.params : {};
      const resolvedGroupId = kind === 'group' ? resolveStructureGroupIdForReplay(params) : '';
      console.info('[public_upload][pins] replay run', {
        category: kind,
        pinCount: pins.length,
        resolvedGroupId,
        requestedGroupId: params?.groupId,
        groupSourceKey: params?.groupSourceKey,
        groupSourceLabel: params?.groupSourceLabel,
      });
      if (kind === 'group' && !resolvedGroupId) {
        unresolvedGroupReference = true;
        console.warn('[group_rail replay] group resolve failed', {
          savedGroupId: params?.groupId,
          groupSourceKey: params?.groupSourceKey,
          groupSourceLabel: params?.groupSourceLabel,
          range: params?.range,
        });
        return;
      }
      runRailConstructionByCategory(kind, {
        pinsPayload: pins,
        groupId: kind === 'group' ? resolvedGroupId : params.groupId,
        lateralOffset: params.lateralOffset,
        verticalOffset: params.verticalOffset,
        yawOffsetDeg: params.yawOffsetDeg,
        spacing: params.spacing,
      });
      run.replayDone = true;
    });
    const hasRemainingRuns = structureGenerationRuns.some((run) => !run?.replayDone);
    console.info('[public_upload][pins] replay result', {
      pendingRunCount,
      hasRemainingRuns,
      unresolvedGroupReference,
    });
    if (hasRemainingRuns && unresolvedGroupReference && structureGenerationReplayRetryCount < STRUCTURE_GENERATION_REPLAY_MAX_RETRY) {
      structureGenerationReplayRetryCount += 1;
      scheduleReplayStructureGenerationRuns();
      return false;
    }
    if (hasRemainingRuns && unresolvedGroupReference) {
      console.warn('[group_rail replay] unresolved runs remain after max retry');
    }
    if (pendingRunCount < 1 || !hasRemainingRuns) {
      structureGenerationReplayPending = false;
      return true;
    }
    structureGenerationReplayPending = false;
  } finally {
    structureGenerationReplayActive = false;
  }
}

function buildStructurePayload() {
  const dedupedRuns = dedupeGenerationRuns(structureGenerationRuns);
  if (dedupedRuns.length !== structureGenerationRuns.length) {
    structureGenerationRuns = dedupedRuns.map((run) => ({
      ...run,
      replayDone: Boolean(run?.replayDone),
    }));
  }
  return {
    meta: {
      version: 3,
      savedAt: new Date().toISOString(),
    },
    pins: structurePinnedPins.map((pin) => ({
      x: pin.position.x,
      y: pin.position.y,
      z: pin.position.z,
      trackName: pin.userData?.trackName ?? null,
      linkedStructureObjectIds: Array.isArray(pin?.userData?.linkedStructureObjectIds)
        ? pin.userData.linkedStructureObjectIds
          .map((v) => String(v || '').trim())
          .filter((v) => v.length > 0)
        : [],
    })),
    generationRuns: structureGenerationRuns.map((run) => ({
      category: String(run?.category || '').trim(),
      pins: normalizePinsPayload(run?.pins),
      params: (run?.params && typeof run.params === 'object') ? { ...run.params } : {},
    })).filter((run) => run.category && run.pins.length > 0),
  };
}

function buildStructurePayloadForGroup(groupId) {
  const id = String(groupId || '').trim();
  if (!id) { return null; }

  const guideGridStatesAll = guideAddGrids
    .filter((grid) => grid?.parent)
    .map((grid) => serializeGuideGridState(grid))
    .filter(Boolean);
  const { gridToKey } = buildGuideGridSaveKeyMapsForPayload(guideGridStatesAll);
  const steelFrameAll = serializeSteelFrameState(gridToKey);
  const decorationsAll = serializeDecorationsState(gridToKey);

  const pointByKey = new Map(
    (Array.isArray(steelFrameAll?.points) ? steelFrameAll.points : [])
      .map((point) => [String(point?.key || '').trim(), point])
      .filter(([key]) => key.length > 0)
  );
  const groupedSegments = (Array.isArray(steelFrameAll?.segments) ? steelFrameAll.segments : [])
    .filter((seg) => String(seg?.structureGroupId || '').trim() === id);
  const usedPointKeys = new Set();
  groupedSegments.forEach((seg) => {
    const keys = Array.isArray(seg?.pointKeys) ? seg.pointKeys : [];
    keys.forEach((key) => {
      const k = String(key || '').trim();
      if (k) { usedPointKeys.add(k); }
    });
  });
  const groupedPoints = Array.from(usedPointKeys)
    .map((key) => pointByKey.get(key) || null)
    .filter(Boolean);
  const groupedDecorations = decorationsAll
    .filter((state) => String(state?.structureGroupId || '').trim() === id);
  if (groupedSegments.length < 1 && groupedDecorations.length < 1) { return null; }

  const groupMembers = getConstructionCopyTargets()
    .filter((mesh) => mesh?.parent)
    .filter((mesh) => !mesh?.userData?.steelFramePoint)
    .filter((mesh) => String(mesh?.userData?.structureGroupId || '').trim() === id);

  const groupObjectIds = new Set(
    groupMembers
      .map((mesh) => ensureStructureObjectId(mesh))
      .filter((objId) => String(objId || '').trim().length > 0)
  );

  const groupRuns = structureGenerationRuns
    .map((run) => {
      const category = String(run?.category || '').trim();
      if (category !== 'group') { return null; }
      const params = (run?.params && typeof run.params === 'object') ? run.params : {};
      const runGroupId = String(params?.groupId || '').trim();
      if (runGroupId !== id) { return null; }
      const pins = normalizePinsPayload(run?.pins);
      if (pins.length < 1) { return null; }
      return {
        category,
        pins,
        params: { ...params },
      };
    })
    .filter(Boolean);

  const copiedGroupEntry = (() => {
    const all = collectCopiedStructureGroupsForSave();
    return all.find((entry) => String(entry?.groupId || '').trim() === id) || null;
  })();
  if (copiedGroupEntry) {
    return {
      meta: {
        version: 4,
        savedAt: new Date().toISOString(),
        groupId: id,
        mode: 'group_copy_reference',
        memberCount: groupMembers.length,
      },
      guideAddGrids: [],
      steelFrame: {
        points: [],
        segments: [],
        copiedInstances: [],
      },
      decorations: [],
      pins: [],
      generationRuns: [],
      copiedStructureGroups: [copiedGroupEntry],
    };
  }

  const pins = structurePinnedPins
    .filter((pin) => pin?.parent)
    .map((pin) => {
      const linkedIds = Array.isArray(pin?.userData?.linkedStructureObjectIds)
        ? pin.userData.linkedStructureObjectIds.map((v) => String(v || '').trim()).filter(Boolean)
        : [];
      const isLinkedToGroup = linkedIds.some((objId) => groupObjectIds.has(objId));
      if (!isLinkedToGroup) { return null; }
      return {
        x: pin.position.x,
        y: pin.position.y,
        z: pin.position.z,
        trackName: pin.userData?.trackName ?? null,
        linkedStructureObjectIds: linkedIds.filter((objId) => groupObjectIds.has(objId)),
      };
    })
    .filter(Boolean);

  const dedupedRuns = dedupeGenerationRuns(groupRuns);

  const compactGroupedSteelFrameForSave = (points, segments, members) => {
    const segmentStates = Array.isArray(segments) ? segments : [];
    const pointStates = Array.isArray(points) ? points : [];
    const keptSegments = [];
    const usedPointKeysLocal = new Set();

    segmentStates.forEach((seg) => {
      keptSegments.push({
        ...seg,
        steelFrameCopiedObject: false,
        steelFrameCopyGroupId: null,
        copyObjectSourceRefId: null,
        copyObjectRefId: null,
      });
      const keys = Array.isArray(seg?.pointKeys) ? seg.pointKeys : [];
      keys.forEach((k) => {
        const key = String(k || '').trim();
        if (key) { usedPointKeysLocal.add(key); }
      });
    });

    const pointByKeyLocal = new Map(
      pointStates
        .map((point) => [String(point?.key || '').trim(), point])
        .filter(([key]) => key.length > 0)
    );
    const keptPoints = Array.from(usedPointKeysLocal)
      .map((key) => pointByKeyLocal.get(key) || null)
      .filter(Boolean)
      .map((point) => ({
        ...point,
        steelFrameCopied: false,
        steelFrameCopyGroupId: null,
      }));

    return {
      points: keptPoints,
      segments: keptSegments,
      copiedInstances: [],
    };
  };

  const compactSteelFrame = compactGroupedSteelFrameForSave(groupedPoints, groupedSegments, groupMembers);

  const requiredGuideKeys = new Set();
  groupedPoints.forEach((point) => {
    const key = String(point?.planeRefKey || '').trim();
    if (key && key !== 'base') { requiredGuideKeys.add(key); }
  });
  groupedDecorations.forEach((state) => {
    const key = String(state?.planeRefKey || '').trim();
    if (key && key !== 'base') { requiredGuideKeys.add(key); }
  });
  const guideStateByKey = new Map(
    guideGridStatesAll
      .map((state) => [String(state?.saveKey || '').trim(), state])
      .filter(([key]) => key.length > 0)
  );
  const queue = Array.from(requiredGuideKeys);
  for (let i = 0; i < queue.length; i += 1) {
    const currentKey = queue[i];
    const state = guideStateByKey.get(currentKey);
    if (!state) { continue; }
    const sourceKey = String(state?.mirroredFromSourceGridKey || '').trim();
    if (sourceKey && sourceKey !== 'base' && !requiredGuideKeys.has(sourceKey)) {
      requiredGuideKeys.add(sourceKey);
      queue.push(sourceKey);
    }
  }
  const groupedGuideGridStates = guideGridStatesAll
    .filter((state) => {
      const key = String(state?.saveKey || '').trim();
      return Boolean(key && requiredGuideKeys.has(key));
    })
    .map((state) => ({ ...state }));
  const groupPose = computeStructureGroupPoseFromMembers(groupMembers);
  const groupRotation = groupPose?.quaternion?.isQuaternion
    ? getGroupRotationAnglesFromQuat(groupPose.quaternion)
    : null;

  return {
    meta: {
      version: 3,
      savedAt: new Date().toISOString(),
      groupId: id,
      mode: 'group_only_with_guides',
      memberCount: groupMembers.length,
      rotation: groupRotation,
    },
    guideAddGrids: groupedGuideGridStates,
    steelFrame: {
      points: compactSteelFrame.points,
      segments: compactSteelFrame.segments,
      copiedInstances: compactSteelFrame.copiedInstances,
    },
    decorations: groupedDecorations,
    pins,
    generationRuns: dedupedRuns,
  };
}

function downloadStructureData() {
  const payload = buildStructurePayload();
  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = 'structure.json';
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
  alert('structure.json を保存しました。');
}

const saveStructureGroupButton = document.getElementById('save-structure-group-data');

function resolveGroupIdForStructureSave() {
  const selectedId = getSelectedSingleStructureGroupId();
  if (selectedId) { return selectedId; }
  const appendId = String(selectedAppendGroupId || '').trim();
  if (appendId) { return appendId; }
  const panelId = String(groupModeIdSelect?.value || '').trim();
  if (panelId) { return panelId; }
  const railId = String(selectedRailConstructionGroupId || '').trim();
  if (railId) { return railId; }
  return '';
}

function downloadStructureGroupData() {
  const groupId = resolveGroupIdForStructureSave();
  if (!groupId) {
    alert('保存対象のグループIDが選択されていません。GROUPモードで同一グループを選択するか、既存グループIDを選んでください。');
    return;
  }
  const payload = buildStructurePayloadForGroup(groupId);
  if (!payload) {
    alert(`グループ保存対象がありません: ${groupId}`);
    return;
  }
  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = `${groupId}.json`;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
  console.log('[group_save] saved group:', {
    groupId,
    fileName: `${groupId}.json`,
    mode: payload?.meta?.mode || null,
    memberCount: Number(payload?.meta?.memberCount) || null,
  });
  alert(`グループ保存しました: ${groupId}`);
}

const saveButtonsContainer = document.getElementById('save-buttons');
if (saveButtonsContainer) {
  // グローバルの mousedown / touchstart ハンドラに吸われないようにする
  const stopPointerPropagation = (event) => {
    event.stopPropagation();
  };
  saveButtonsContainer.addEventListener('mousedown', stopPointerPropagation);
  saveButtonsContainer.addEventListener('touchstart', stopPointerPropagation, { passive: true });
  saveButtonsContainer.addEventListener('pointerdown', stopPointerPropagation);
}

function serializeDifferenceSpaceMesh(mesh) {
  const railTrackNames = Array.isArray(mesh?.userData?.differenceRailTrackNames)
    ? mesh.userData.differenceRailTrackNames
      .map((name) => String(name || '').trim())
      .filter((name) => name.length > 0)
    : [];
  if (railTrackNames.length > 0) {
    return {
      mode: 'rail_track_names',
      trackNames: railTrackNames,
      bandHeight: Number(mesh?.userData?.differenceRailBandHeight) || readDifferenceLineBandHeight(),
      sidePadding: Number(mesh?.userData?.differenceRailSidePadding) || 0.6,
      innerPadding: Number(mesh?.userData?.differenceRailInnerPadding) || 0.6,
      minBandWidth: Number(mesh?.userData?.differenceRailMinBandWidth) || 1.2,
      sampleStepMeters: Number(mesh?.userData?.differenceRailSampleStepMeters) || 2.0,
    };
  }
  if (!mesh?.geometry?.attributes?.position) { return null; }
  const positionAttr = mesh.geometry.attributes.position;
  const indexAttr = mesh.geometry.getIndex();
  return {
    position: [mesh.position.x, mesh.position.y, mesh.position.z],
    quaternion: [mesh.quaternion.x, mesh.quaternion.y, mesh.quaternion.z, mesh.quaternion.w],
    scale: [mesh.scale.x, mesh.scale.y, mesh.scale.z],
    geometry: {
      position: Array.from(positionAttr.array),
      index: indexAttr ? Array.from(indexAttr.array) : null,
    },
  };
}

function normalizeDifferenceRailOperation(rawOperation) {
  const trackNames = Array.isArray(rawOperation?.trackNames)
    ? rawOperation.trackNames.map((name) => String(name || '').trim()).filter((name) => name.length > 0)
    : [];
  if (trackNames.length < 1) { return null; }
  return {
    mode: 'rail_track_names',
    trackNames,
    bandHeight: Number(rawOperation?.bandHeight) || readDifferenceLineBandHeight(),
    sidePadding: Number(rawOperation?.sidePadding) || 0.6,
    innerPadding: Number(rawOperation?.innerPadding) || 0.6,
    minBandWidth: Number(rawOperation?.minBandWidth) || 1.2,
    sampleStepMeters: Number(rawOperation?.sampleStepMeters) || 2.0,
  };
}

function serializeDifferenceRailOperations() {
  return differenceRailOperations
    .map((operation) => normalizeDifferenceRailOperation(operation))
    .filter(Boolean);
}

function buildDifferenceRailOperationFromCutter(sourceMesh) {
  return normalizeDifferenceRailOperation({
    trackNames: Array.isArray(sourceMesh?.userData?.differenceRailTrackNames)
      ? sourceMesh.userData.differenceRailTrackNames
      : [],
    bandHeight: Number(sourceMesh?.userData?.differenceRailBandHeight),
    sidePadding: Number(sourceMesh?.userData?.differenceRailSidePadding),
    innerPadding: Number(sourceMesh?.userData?.differenceRailInnerPadding),
    minBandWidth: Number(sourceMesh?.userData?.differenceRailMinBandWidth),
    sampleStepMeters: Number(sourceMesh?.userData?.differenceRailSampleStepMeters),
  });
}

function resolveDifferenceLineTrackNamesForExecution(rawTrackNames = null) {
  const normalized = normalizeDifferenceLineTrackNames(
    Array.isArray(rawTrackNames) && rawTrackNames.length > 0
      ? rawTrackNames
      : differenceLineTrackNames
  );
  if (normalized.length > 0) {
    return normalized;
  }
  return Array.isArray(railTrackDefs)
    ? railTrackDefs
      .map((track) => String(track?.name || '').trim())
      .filter((name) => name.length > 0)
    : [];
}

function buildDifferenceRailOperationFromTrackNames(trackNames, overrides = {}) {
  return normalizeDifferenceRailOperation({
    trackNames: resolveDifferenceLineTrackNamesForExecution(trackNames),
    bandHeight: overrides?.bandHeight,
    sidePadding: overrides?.sidePadding,
    innerPadding: overrides?.innerPadding,
    minBandWidth: overrides?.minBandWidth,
    sampleStepMeters: overrides?.sampleStepMeters,
  });
}

function buildGuideGridSaveKeyMapsForPayload(guideGridStates) {
  const gridToKey = new Map();
  const keyToGrid = new Map();
  gridToKey.set(AddPointGuideGrid, 'base');
  keyToGrid.set('base', AddPointGuideGrid);
  AddPointGuideGrid.userData = {
    ...(AddPointGuideGrid.userData || {}),
    saveKey: 'base',
  };
  const liveGuideGrids = guideAddGrids.filter((grid) => grid?.parent);
  liveGuideGrids.forEach((grid, idx) => {
    const key = `g${idx}`;
    gridToKey.set(grid, key);
    keyToGrid.set(key, grid);
    grid.userData = {
      ...(grid.userData || {}),
      saveKey: key,
    };
    if (guideGridStates[idx] && typeof guideGridStates[idx] === 'object') {
      guideGridStates[idx].saveKey = key;
    }
  });
  guideGridStates.forEach((state) => {
    if (!state || typeof state !== 'object') { return; }
    if (!state.saveKey && state.name === 'AddPointGuideGrid') {
      state.saveKey = 'base';
    }
    const sourceId = Number(state.mirroredFromSourceGridId) || null;
    if (!sourceId) { return; }
    const sourceGrid = (sourceId === AddPointGuideGrid.id)
      ? AddPointGuideGrid
      : (liveGuideGrids.find((g) => g?.id === sourceId) || null);
    const sourceKey = sourceGrid ? (gridToKey.get(sourceGrid) || (sourceGrid === AddPointGuideGrid ? 'base' : null)) : null;
    if (sourceKey) {
      state.mirroredFromSourceGridKey = sourceKey;
    }
  });
  return { gridToKey, keyToGrid };
}

function normalizeSteelFrameSegmentProfile(rawProfile) {
  const p = String(rawProfile || 'round').toLowerCase();
  if (p === 'round' || p === 'rect_bar' || p === 'corrugated_bar' || p === 'h_beam' || p === 't_beam' || p === 'l_beam' || p === 'tubular' || p === 'tube' || p === 'panel_wall') {
    return p;
  }
  if (p === 'corrugated' || p === 'corrugation' || p === 'wave' || p === 'wave_plate') {
    return 'corrugated_bar';
  }
  return 'round';
}

function normalizeSerializedSegmentStyle(profile, rawStyle) {
  if (!rawStyle || typeof rawStyle !== 'object') { return null; }
  const style = {
    beamWidthHorizontal: Number(rawStyle.beamWidthHorizontal),
    beamHeightVertical: Number(rawStyle.beamHeightVertical),
    beamThickness: Number(rawStyle.beamThickness),
  };
  const out = {};
  if (Number.isFinite(style.beamWidthHorizontal)) { out.beamWidthHorizontal = style.beamWidthHorizontal; }
  if (Number.isFinite(style.beamHeightVertical)) { out.beamHeightVertical = style.beamHeightVertical; }
  if (Number.isFinite(style.beamThickness)) { out.beamThickness = style.beamThickness; }

  if (profile === 'corrugated_bar') {
    // 旧データ互換:
    // - Y が波高だった時代の値(<=1.0程度)は角度0へ
    // - Z が板厚だった時代の値(<0.3)は既定波密度へ
    if (Number.isFinite(out.beamHeightVertical) && Math.abs(out.beamHeightVertical) <= 1.0) {
      out.beamHeightVertical = 0;
    }
    if (Number.isFinite(out.beamThickness) && out.beamThickness < 0.3) {
      out.beamThickness = 5.0;
    }
  }
  return out;
}

function serializeSteelFrameState(gridToKey = new Map(), options = {}) {
  const excludedGroupIds = options?.excludedGroupIds instanceof Set
    ? options.excludedGroupIds
    : new Set();
  const excludeCopiedObjects = options?.excludeCopiedObjects === true;
  const excludeCopiedGroupObjects = options?.excludeCopiedGroupObjects === true;
  const materializeCopiedObjects = options?.materializeCopiedObjects === true;
  const points = (steelFrameMode?.getAllPointMeshes?.() || [])
    .filter((mesh) => mesh?.userData?.steelFramePoint && mesh?.parent);
  const pointKeyByMesh = new Map();
  const pointStates = points.map((mesh, idx) => {
    const shouldMaterializeCopy = materializeCopiedObjects
      && !String(mesh?.userData?.structureGroupId || '').trim()
      && (Boolean(mesh?.userData?.steelFrameCopied) || Boolean(String(mesh?.userData?.steelFrameCopyGroupId || '').trim()));
    const key = `p${idx}`;
    pointKeyByMesh.set(mesh, key);
    const pref = mesh?.userData?.planeRef || null;
    const planeRefKey = pref && gridToKey.has(pref) ? gridToKey.get(pref) : null;
    return {
      key,
      lineIndex: Number.isInteger(mesh?.userData?.steelFrameLine) ? mesh.userData.steelFrameLine : 0,
      position: [mesh.position.x, mesh.position.y, mesh.position.z],
      scale: [mesh.scale.x, mesh.scale.y, mesh.scale.z],
      steelFrameCopied: shouldMaterializeCopy ? false : Boolean(mesh?.userData?.steelFrameCopied),
      steelFrameCopyGroupId: shouldMaterializeCopy ? null : (mesh?.userData?.steelFrameCopyGroupId ?? null),
      planeRefKey,
    };
  });

  const segments = (steelFrameMode?.getSegmentMeshes?.() || [])
    .filter((mesh) => mesh?.parent && mesh?.name === 'SteelFrameSegment')
    .filter((mesh) => {
      const gid = String(mesh?.userData?.structureGroupId || '').trim();
      return !gid || !excludedGroupIds.has(gid);
    })
    .filter((mesh) => {
      if (!excludeCopiedGroupObjects) { return true; }
      const copySourceId = String(mesh?.userData?.structureGroupCopySourceId || '').trim();
      const railPlacementGroupId = String(mesh?.userData?.railPlacementGroupId || '').trim();
      return !(copySourceId || railPlacementGroupId);
    })
    .filter((mesh) => {
      if (!excludeCopiedObjects) { return true; }
      const isCopiedObject = Boolean(mesh?.userData?.steelFrameCopiedObject);
      const copyGroupId = String(mesh?.userData?.steelFrameCopyGroupId || '').trim();
      const copySourceRefId = String(mesh?.userData?.copyObjectSourceRefId || '').trim();
      return !(isCopiedObject || copyGroupId || copySourceRefId);
    });
  const segmentStates = segments.map((mesh) => {
    const refs = Array.isArray(mesh?.userData?.steelFrameSegmentPointRefs)
      ? mesh.userData.steelFrameSegmentPointRefs
      : [];
    const refKeys = refs.map((p) => pointKeyByMesh.get(p) || null).filter(Boolean);
    const profile = normalizeSteelFrameSegmentProfile(mesh?.userData?.steelFrameSegmentProfile || 'round');
    const shouldMaterializeCopy = materializeCopiedObjects
      && !String(mesh?.userData?.structureGroupId || '').trim()
      && (
        Boolean(mesh?.userData?.steelFrameCopiedObject)
        || Boolean(String(mesh?.userData?.steelFrameCopyGroupId || '').trim())
        || Boolean(String(mesh?.userData?.copyObjectSourceRefId || '').trim())
      );
    return {
      pointKeys: refKeys,
      profile,
      style: normalizeSerializedSegmentStyle(profile, mesh?.userData?.steelFrameSegmentStyle || null),
      scale: [mesh.scale.x, mesh.scale.y, mesh.scale.z],
      steelFrameCopiedObject: shouldMaterializeCopy ? false : Boolean(mesh?.userData?.steelFrameCopiedObject),
      steelFrameCopyGroupId: shouldMaterializeCopy ? null : (mesh?.userData?.steelFrameCopyGroupId ?? null),
      structureGroupId: mesh?.userData?.structureGroupId ?? null,
      structureGroupScale: Number(mesh?.userData?.structureGroupScale) || null,
      copyObjectSourceRefId: shouldMaterializeCopy ? null : (mesh?.userData?.copyObjectSourceRefId ?? null),
      copyObjectRefId: shouldMaterializeCopy ? null : (mesh?.userData?.copyObjectRefId ?? null),
    };
  });

  const usedPointKeys = new Set();
  segmentStates.forEach((segment) => {
    const keys = Array.isArray(segment?.pointKeys) ? segment.pointKeys : [];
    keys.forEach((key) => {
      const normalized = String(key || '').trim();
      if (normalized) { usedPointKeys.add(normalized); }
    });
  });
  const filteredPointStates = pointStates
    .filter((point) => usedPointKeys.has(String(point?.key || '').trim()))
    .filter((point) => {
      if (!excludeCopiedObjects) { return true; }
      const copied = Boolean(point?.steelFrameCopied);
      const copyGroupId = String(point?.steelFrameCopyGroupId || '').trim();
      return !(copied || copyGroupId);
    });

  return {
    points: filteredPointStates,
    segments: segmentStates,
  };
}

function clearSteelFrameForImport() {
  const segs = (steelFrameMode?.getSegmentMeshes?.() || []).slice();
  segs.forEach((mesh) => {
    steelFrameMode?.removeExistingSegmentMesh?.(mesh);
    if (mesh?.parent) { mesh.parent.remove(mesh); }
    mesh?.traverse?.((node) => {
      node?.geometry?.dispose?.();
      if (Array.isArray(node?.material)) {
        node.material.forEach((m) => m?.dispose?.());
      } else {
        node?.material?.dispose?.();
      }
    });
  });
  const points = (steelFrameMode?.getAllPointMeshes?.() || []).slice();
  points.forEach((mesh) => {
    steelFrameMode?.removePointMesh?.(mesh);
  });
  steelFrameMode?.clearSelection?.();
  clearCopySelection?.();
  clearGroupSelection?.();
  clearDeleteSelection?.();
}

function restoreSteelFrameState(payloadSteelFrame, keyToGrid = new Map()) {
  if (!payloadSteelFrame || typeof payloadSteelFrame !== 'object') { return; }
  const pointStates = Array.isArray(payloadSteelFrame.points) ? payloadSteelFrame.points : [];
  const segmentStates = Array.isArray(payloadSteelFrame.segments) ? payloadSteelFrame.segments : [];
  const copiedInstances = Array.isArray(payloadSteelFrame.copiedInstances) ? payloadSteelFrame.copiedInstances : [];
  const pointMap = new Map();
  const usedCopyRefIds = new Set();
  const copyRefAliasMap = new Map();
  const reserveUniqueCopyRefId = (preferredRefId = '') => {
    const preferred = String(preferredRefId || '').trim();
    if (preferred && !usedCopyRefIds.has(preferred)) {
      usedCopyRefIds.add(preferred);
      return preferred;
    }
    let next = '';
    do {
      next = `copy_obj_${copyObjectRegistrySeq}`;
      copyObjectRegistrySeq += 1;
    } while (usedCopyRefIds.has(next));
    usedCopyRefIds.add(next);
    return next;
  };

  pointStates.forEach((p) => {
    if (!Array.isArray(p?.position) || p.position.length < 3) { return; }
    const mesh = new THREE.Mesh(cube_geometry, cube_material.clone());
    mesh.position.set(Number(p.position[0]) || 0, Number(p.position[1]) || 0, Number(p.position[2]) || 0);
    if (Array.isArray(p?.scale) && p.scale.length >= 3) {
      mesh.scale.set(Number(p.scale[0]) || 1, Number(p.scale[1]) || 1, Number(p.scale[2]) || 1);
    }
    const planeRef = typeof p?.planeRefKey === 'string' ? (keyToGrid.get(p.planeRefKey) || null) : null;
    mesh.userData = {
      ...(mesh.userData || {}),
      steelFramePoint: true,
      steelFrameLine: Number.isInteger(p?.lineIndex) ? p.lineIndex : 0,
      steelFrameCopied: Boolean(p?.steelFrameCopied),
      steelFrameCopyGroupId: p?.steelFrameCopyGroupId ?? null,
      planeRef: planeRef || null,
    };
    steelFrameMode?.addExistingPoint?.(mesh, mesh.userData.steelFrameLine);
    if (Boolean(p?.steelFrameCopied) && mesh?.material?.color?.setHex) {
      mesh.material.color.setHex(0xffd400);
    }
    if (typeof p?.key === 'string') {
      pointMap.set(p.key, mesh);
    }
  });

  segmentStates.forEach((s) => {
    const keys = Array.isArray(s?.pointKeys) ? s.pointKeys : [];
    if (keys.length < 2) { return; }
    const pointRefs = keys
      .map((k) => pointMap.get(k) || null)
      .filter((mesh) => mesh?.userData?.steelFramePoint);
    const p0 = pointRefs[0] || null;
    const p1 = pointRefs[1] || null;
    if (!p0 || !p1) { return; }
    const normalizedProfile = normalizeSteelFrameSegmentProfile(s?.profile || 'round');
    // 互換救済:
    // 旧保存で panel_wall が round に落ちていたデータは pointKeys が4点で残っているため、
    // ロード時に panel_wall として扱って復元する。
    const profile = (normalizedProfile === 'round' && keys.length >= 4)
      ? 'panel_wall'
      : normalizedProfile;
    const style = normalizeSerializedSegmentStyle(profile, s?.style);
    const rawCopyRefId = String(s?.copyObjectRefId || '').trim();
    const assignedCopyRefId = reserveUniqueCopyRefId(rawCopyRefId);
    if (rawCopyRefId && !copyRefAliasMap.has(rawCopyRefId)) {
      copyRefAliasMap.set(rawCopyRefId, assignedCopyRefId);
    }
    const seg = steelFrameMode?.createSegmentBetweenPoints?.(p0, p1, {
      profile,
      style,
      userData: {
        steelFrameCopiedObject: Boolean(s?.steelFrameCopiedObject),
        steelFrameCopyGroupId: s?.steelFrameCopyGroupId ?? null,
        structureGroupId: s?.structureGroupId ?? null,
        structureGroupScale: Number(s?.structureGroupScale) || null,
        copyObjectSourceRefId: s?.copyObjectSourceRefId ?? null,
        copyObjectRefId: assignedCopyRefId || null,
      },
    });
    if (!seg) { return; }
    if (Array.isArray(s?.scale) && s.scale.length >= 3) {
      seg.scale.set(Number(s.scale[0]) || 1, Number(s.scale[1]) || 1, Number(s.scale[2]) || 1);
    }
    if (Boolean(s?.steelFrameCopiedObject)) {
      setCopyObjectVisual(seg, false);
    }
    if ((profile === 'tube' && pointRefs.length >= 2) || (profile === 'panel_wall' && pointRefs.length >= 4)) {
      seg.userData = {
        ...(seg.userData || {}),
        steelFrameSegmentPointRefs: pointRefs,
      };
      steelFrameMode?.rebuildSegmentsForMeshes?.([seg]);
    }
    enforceTubeSegmentBlack(seg);
    registerCopyObject(seg);
  });

  const restoreCopiedInstances = (instances) => {
    const list = Array.isArray(instances) ? instances : [];
    list.forEach((inst) => {
      const sourceRefIdRaw = String(inst?.sourceRefId || '').trim();
      if (!sourceRefIdRaw) { return; }
      const sourceRefId = copyRefAliasMap.get(sourceRefIdRaw) || sourceRefIdRaw;
      const sourceMesh = copyObjectRegistry.get(sourceRefId);
      if (!sourceMesh?.parent || sourceMesh?.name !== 'SteelFrameSegment') { return; }
      const instanceCopyRefIdRaw = String(inst?.copyObjectRefId || '').trim();
      const instanceCopyRefId = reserveUniqueCopyRefId(instanceCopyRefIdRaw);

      const pos = Array.isArray(inst?.position) ? inst.position : [sourceMesh.position.x, sourceMesh.position.y, sourceMesh.position.z];
      const quat = Array.isArray(inst?.quaternion) ? inst.quaternion : [sourceMesh.quaternion.x, sourceMesh.quaternion.y, sourceMesh.quaternion.z, sourceMesh.quaternion.w];
      const scl = Array.isArray(inst?.scale) ? inst.scale : [sourceMesh.scale.x, sourceMesh.scale.y, sourceMesh.scale.z];
      const targetPos = new THREE.Vector3(Number(pos[0]) || 0, Number(pos[1]) || 0, Number(pos[2]) || 0);
      const targetQuat = new THREE.Quaternion(Number(quat[0]) || 0, Number(quat[1]) || 0, Number(quat[2]) || 0, Number(quat[3]) || 1).normalize();
      const targetScale = new THREE.Vector3(Number(scl[0]) || 1, Number(scl[1]) || 1, Number(scl[2]) || 1);

      const sourceRefs = Array.isArray(sourceMesh?.userData?.steelFrameSegmentPointRefs)
        ? sourceMesh.userData.steelFrameSegmentPointRefs.filter((p) => p?.userData?.steelFramePoint)
        : [];
      const sourceProfile = normalizeSteelFrameSegmentProfile(inst?.profile || sourceMesh?.userData?.steelFrameSegmentProfile || 'round');
      const sourceStyle = normalizeSerializedSegmentStyle(sourceProfile, inst?.style || sourceMesh?.userData?.steelFrameSegmentStyle || null);
      const sourceGroupId = inst?.structureGroupId ?? sourceMesh?.userData?.structureGroupId ?? null;
      const sourceGroupScale = Number(inst?.structureGroupScale ?? sourceMesh?.userData?.structureGroupScale ?? 1) || 1;
      const copyGroupId = inst?.steelFrameCopyGroupId ?? sourceMesh?.userData?.steelFrameCopyGroupId ?? null;
      const sourceObjPos = sourceMesh.position.clone();
      const sourceObjQuat = sourceMesh.quaternion.clone();
      const sourceObjScale = sourceMesh.scale.clone();
      const sourceMatrix = new THREE.Matrix4().compose(sourceObjPos, sourceObjQuat, sourceObjScale);
      const targetMatrix = new THREE.Matrix4().compose(targetPos, targetQuat, targetScale);
      const deltaMatrix = new THREE.Matrix4().multiplyMatrices(targetMatrix, sourceMatrix.clone().invert());

      if (sourceRefs.length >= 2) {
        const srcToDstPoint = new Map();
        const ensureCopiedPointFromSource = (srcPoint) => {
          const existing = srcToDstPoint.get(srcPoint);
          if (existing?.parent) { return existing; }
          const lineIndex = Number.isInteger(srcPoint?.userData?.steelFrameLine) ? srcPoint.userData.steelFrameLine : 0;
          const nextPos = srcPoint.position.clone().applyMatrix4(deltaMatrix);
          const mesh = new THREE.Mesh(cube_geometry, cube_material.clone());
          mesh.position.copy(nextPos);
          mesh.scale.copy(srcPoint.scale);
          mesh.userData = {
            ...(srcPoint.userData || {}),
            steelFramePoint: true,
            steelFrameLine: lineIndex,
            steelFrameCopied: true,
            steelFrameCopyGroupId: copyGroupId || srcPoint?.userData?.steelFrameCopyGroupId || null,
            structureGroupScale: sourceGroupScale,
          };
          delete mesh.userData.guideCurve;
          delete mesh.userData.guideControlIndex;
          steelFrameMode?.addExistingPoint?.(mesh, lineIndex);
          srcToDstPoint.set(srcPoint, mesh);
          return mesh;
        };

        const copiedRefs = sourceRefs.map((srcPoint) => ensureCopiedPointFromSource(srcPoint)).filter(Boolean);
        const p0 = copiedRefs[0] || null;
        const p1 = copiedRefs[1] || null;
        if (!p0 || !p1) { return; }
        const seg = steelFrameMode?.createSegmentBetweenPoints?.(p0, p1, {
          profile: sourceProfile,
          style: sourceStyle,
          userData: {
            ...(sourceMesh.userData || {}),
            steelFrameSegmentPointRefs: copiedRefs,
            steelFrameCopiedObject: true,
            copyObjectSourceRefId: sourceRefId,
            copyObjectRefId: instanceCopyRefId,
            steelFrameCopyGroupId: copyGroupId || null,
            structureGroupId: sourceGroupId,
      structureGroupScale: sourceGroupScale,
    },
  });
        if (!seg) { return; }
        if ((sourceProfile === 'tube' && copiedRefs.length >= 2) || (sourceProfile === 'panel_wall' && copiedRefs.length >= 4)) {
          seg.userData = {
            ...(seg.userData || {}),
            steelFrameSegmentPointRefs: copiedRefs,
          };
          steelFrameMode?.rebuildSegmentsForMeshes?.([seg]);
        }
        enforceTubeSegmentBlack(seg);
        setCopyObjectVisual(seg, false);
        registerCopyObject(seg);
        return;
      }

      const cloned = cloneObjectVisualTreeWithoutUserData(sourceMesh) || sourceMesh.clone?.(true);
      if (!cloned) { return; }
      cloned.position.copy(targetPos);
      cloned.quaternion.copy(targetQuat);
      cloned.scale.copy(targetScale);
      cloned.userData = {
        ...(sourceMesh.userData || {}),
        steelFrameSegmentPointRefs: [],
        steelFrameCopiedObject: true,
        copyObjectSourceRefId: sourceRefId,
        copyObjectRefId: instanceCopyRefId,
        steelFrameCopyGroupId: copyGroupId || null,
        structureGroupId: sourceGroupId,
        structureGroupScale: sourceGroupScale,
      };
      scene.add(cloned);
      steelFrameMode?.addExistingSegmentMesh?.(cloned);
      enforceTubeSegmentBlack(cloned);
      setCopyObjectVisual(cloned, false);
      registerCopyObject(cloned);
    });
  };

  if (copiedInstances.length > 0) {
    restoreCopiedInstances(copiedInstances);
  }
}

function normalizeDecorationType(rawType) {
  const t = String(rawType || '').toLowerCase();
  if (t === 'led_board' || t === 'rect_spot_light') { return t; }
  return null;
}

function serializeDecorationState(mesh, gridToKey = new Map()) {
  const type = normalizeDecorationType(mesh?.userData?.decorationType);
  if (!type || !mesh?.position || !mesh?.quaternion || !mesh?.scale) { return null; }
  const pref = mesh?.userData?.planeRef || null;
  const planeRefKey = pref && gridToKey.has(pref) ? gridToKey.get(pref) : null;
  const out = {
    type,
    position: [mesh.position.x, mesh.position.y, mesh.position.z],
    quaternion: [mesh.quaternion.x, mesh.quaternion.y, mesh.quaternion.z, mesh.quaternion.w],
    scale: [mesh.scale.x, mesh.scale.y, mesh.scale.z],
    planeRefKey,
    baseColor: Number(mesh?.userData?.baseColor) || null,
    structureGroupId: mesh?.userData?.structureGroupId ?? null,
    structureGroupScale: Number(mesh?.userData?.structureGroupScale) || null,
  };
  if (type === 'led_board') {
    out.ledBoardData = mesh?.userData?.ledBoardData && typeof mesh.userData.ledBoardData === 'object'
      ? { ...mesh.userData.ledBoardData }
      : null;
  }
  return out;
}

function serializeDecorationsState(gridToKey = new Map(), options = {}) {
  const excludedGroupIds = options?.excludedGroupIds instanceof Set
    ? options.excludedGroupIds
    : new Set();
  const excludeCopiedGroupObjects = options?.excludeCopiedGroupObjects === true;
  return decorationObjects
    .filter((mesh) => mesh?.parent)
    .filter((mesh) => {
      const gid = String(mesh?.userData?.structureGroupId || '').trim();
      return !gid || !excludedGroupIds.has(gid);
    })
    .filter((mesh) => {
      if (!excludeCopiedGroupObjects) { return true; }
      const copySourceId = String(mesh?.userData?.structureGroupCopySourceId || '').trim();
      const railPlacementGroupId = String(mesh?.userData?.railPlacementGroupId || '').trim();
      return !(copySourceId || railPlacementGroupId);
    })
    .map((mesh) => serializeDecorationState(mesh, gridToKey))
    .filter(Boolean);
}

function clearDecorationsForImport() {
  for (let i = decorationObjects.length - 1; i >= 0; i -= 1) {
    const mesh = decorationObjects[i];
    if (!mesh) { continue; }
    if (mesh.parent) {
      mesh.parent.remove(mesh);
    }
    mesh.traverse?.((node) => {
      node?.geometry?.dispose?.();
      if (Array.isArray(node?.material)) {
        node.material.forEach((m) => m?.dispose?.());
      } else {
        node?.material?.dispose?.();
      }
    });
    decorationObjects.splice(i, 1);
  }
}

function restoreDecorationsState(payloadDecorations, keyToGrid = new Map()) {
  const states = Array.isArray(payloadDecorations) ? payloadDecorations : [];
  states.forEach((state) => {
    const type = normalizeDecorationType(state?.type);
    if (!type) { return; }
    const pos = Array.isArray(state?.position) ? state.position : [0, 0, 0];
    const position = new THREE.Vector3(Number(pos[0]) || 0, Number(pos[1]) || 0, Number(pos[2]) || 0);
    const mesh = type === 'led_board'
      ? createLedBoardDecoration(position)
      : createRectSpotLightDecoration(position);
    if (!mesh) { return; }
    const quat = Array.isArray(state?.quaternion) ? state.quaternion : [0, 0, 0, 1];
    mesh.quaternion.set(Number(quat[0]) || 0, Number(quat[1]) || 0, Number(quat[2]) || 0, Number(quat[3]) || 1);
    const scl = Array.isArray(state?.scale) ? state.scale : [1, 1, 1];
    mesh.scale.set(Number(scl[0]) || 1, Number(scl[1]) || 1, Number(scl[2]) || 1);
    const planeRef = typeof state?.planeRefKey === 'string' ? (keyToGrid.get(state.planeRefKey) || null) : null;
    mesh.userData = {
      ...(mesh.userData || {}),
      planeRef: planeRef || null,
      baseColor: Number(state?.baseColor) || (mesh?.userData?.baseColor || null),
      structureGroupId: state?.structureGroupId ?? null,
      structureGroupScale: Number(state?.structureGroupScale) || null,
    };
    if (type === 'led_board' && state?.ledBoardData && typeof state.ledBoardData === 'object') {
      mesh.userData.ledBoardData = { ...state.ledBoardData };
      renderLedBoardTexture(mesh);
    }
    scene.add(mesh);
    decorationObjects.push(mesh);
  });
}

function buildDifferenceSpacesPayload() {
  const spaces = differenceSpacePlanes
    .filter((mesh) => mesh?.parent && mesh?.userData?.differenceSpacePlane)
    .filter((mesh) => !Array.isArray(mesh?.userData?.differenceRailTrackNames) || mesh.userData.differenceRailTrackNames.length < 1)
    .map((mesh) => serializeDifferenceSpaceMesh(mesh))
    .filter(Boolean);
  const railOperations = serializeDifferenceRailOperations();
  return {
    meta: {
      version: 2,
      type: 'difference_space',
      app: 'Train_EditMode_demo',
      savedAt: new Date().toISOString(),
    },
    differenceSpaces: spaces,
    differenceRailOperations: railOperations,
  };
}

function buildCreateModePayload(options = {}) {
  const includeDifferenceSpaces = options?.includeDifferenceSpaces !== false;
  const materializeCopiedObjects = options?.materializeCopiedObjects === true;
  const excludeCopiedGroupObjects = options?.excludeCopiedGroupObjects === true;
  const excludedGroupIdsOption = options?.excludedGroupIds instanceof Set
    ? options.excludedGroupIds
    : null;
  const uiStateRaw = localStorage.getItem(UI_STATE_STORAGE_KEY);
  let uiState = null;
  try {
    uiState = uiStateRaw ? JSON.parse(uiStateRaw) : null;
  } catch (err) {
    uiState = null;
  }

  const spaces = differenceSpacePlanes
    .filter((mesh) => mesh?.parent && mesh?.userData?.differenceSpacePlane)
    .filter((mesh) => !Array.isArray(mesh?.userData?.differenceRailTrackNames) || mesh.userData.differenceRailTrackNames.length < 1)
    .map((mesh) => serializeDifferenceSpaceMesh(mesh))
    .filter(Boolean);
  const railOperations = serializeDifferenceRailOperations();
  const baseGuideGrid = serializeBaseGuideGridState();
  const guideGridStates = guideAddGrids
    .filter((grid) => grid?.parent)
    .map((grid) => serializeGuideGridState(grid))
    .filter(Boolean);
  const { gridToKey } = buildGuideGridSaveKeyMapsForPayload(guideGridStates);
  // createMode は「非グループ対象」を保存する運用にする。
  const groupedStructureIds = excludedGroupIdsOption || new Set(collectStructureGroupIds());
  const copiedStructureGroups = [];
  const steelFrame = serializeSteelFrameState(gridToKey, {
    excludedGroupIds: groupedStructureIds,
    excludeCopiedGroupObjects,
    excludeCopiedObjects: !materializeCopiedObjects,
    materializeCopiedObjects,
  });
  const decorations = serializeDecorationsState(gridToKey, {
    excludedGroupIds: groupedStructureIds,
    excludeCopiedGroupObjects,
  });

  return {
    meta: {
      version: 1,
      savedAt: new Date().toISOString(),
      app: 'Train_EditMode_demo',
    },
    mode: {
      editObject,
      objectEditMode,
      searchObject: search_object,
      moveDirectionY: move_direction_y,
      differenceSpaceModeActive,
      differenceSpaceTransformMode,
      differenceShapeType,
      differencePathType,
      differenceLineTrackNames: Array.isArray(differenceLineTrackNames)
        ? differenceLineTrackNames.slice()
        : [],
      differenceLineBandHeight,
    },
    uiState,
    baseGuideGrid,
    guideAddGrids: guideGridStates,
    steelFrame,
    decorations,
    copiedStructureGroups,
    trainRunConfigs: trainRunConfigs.map((config) => normalizeTrainRunConfig(config)),
    differenceSpaces: includeDifferenceSpaces ? spaces : [],
    differenceRailOperations: includeDifferenceSpaces ? railOperations : [],
  };
}

function filterCreateModePayloadByExcludedGroupIds(payload, excludedGroupIds) {
  if (!payload || typeof payload !== 'object' || !(excludedGroupIds instanceof Set) || excludedGroupIds.size < 1) {
    return payload;
  }
  const steelFrame = payload?.steelFrame && typeof payload.steelFrame === 'object'
    ? payload.steelFrame
    : {};
  const nextSegments = (Array.isArray(steelFrame?.segments) ? steelFrame.segments : [])
    .filter((segment) => {
      const groupId = String(segment?.structureGroupId || '').trim();
      return !groupId || !excludedGroupIds.has(groupId);
    });
  const usedPointKeys = new Set();
  nextSegments.forEach((segment) => {
    const pointKeys = Array.isArray(segment?.pointKeys) ? segment.pointKeys : [];
    pointKeys.forEach((key) => {
      const normalized = String(key || '').trim();
      if (normalized) {
        usedPointKeys.add(normalized);
      }
    });
  });
  const nextPoints = (Array.isArray(steelFrame?.points) ? steelFrame.points : [])
    .filter((point) => usedPointKeys.has(String(point?.key || '').trim()));
  const nextDecorations = (Array.isArray(payload?.decorations) ? payload.decorations : [])
    .filter((decoration) => {
      const groupId = String(decoration?.structureGroupId || '').trim();
      return !groupId || !excludedGroupIds.has(groupId);
    });
  return {
    ...payload,
    steelFrame: {
      ...steelFrame,
      points: nextPoints,
      segments: nextSegments,
    },
    decorations: nextDecorations,
  };
}

function downloadCreateModeData() {
  const payload = buildCreateModePayload();
  const msgpackBytes = packState(payload);
  const blob = new Blob([msgpackBytes], { type: 'application/x-msgpack' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  const stamp = new Date().toISOString().replace(/[:.]/g, '-');
  link.download = `create_mode_state_${stamp}.msgpack`;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
  alert('create_mode_state.msgpack を保存しました。');
}

function buildTrackPayloadForWorldSave() {
  const tracks = {};
  (Array.isArray(railTrackDefs) ? railTrackDefs : []).forEach((track) => {
    const name = String(track?.name || '').trim();
    const points = Array.isArray(track?.points) ? track.points : [];
    if (!name || points.length < 2) { return; }
    tracks[name] = points.map((point) => ({
      x: Number(point?.x) || 0,
      y: Number(point?.y) || 0,
      z: Number(point?.z) || 0,
    }));
  });
  return {
    meta: {
      version: 1,
      scaled: true,
      scale: WORLD_SCALE,
      savedAt: new Date().toISOString(),
    },
    tracks,
  };
}

function buildWorldPayload() {
  const buildRuntimeGroupCopySourceMap = () => {
    const map = new Map();
    const targets = getConstructionCopyTargets().filter((mesh) => mesh?.parent);
    targets.forEach((mesh) => {
      const gid = String(mesh?.userData?.structureGroupId || '').trim();
      const sourceId = String(mesh?.userData?.structureGroupCopySourceId || '').trim();
      if (!gid || !sourceId) { return; }
      if (!map.has(gid)) {
        map.set(gid, sourceId);
      }
    });
    return map;
  };

  const resolveConcreteSourceGroupIds = (sourceIds, copySourceMap) => {
    const out = new Set();
    sourceIds.forEach((sourceIdRaw) => {
      let current = String(sourceIdRaw || '').trim();
      if (!current) { return; }
      const visited = new Set();
      while (current) {
        if (visited.has(current)) {
          // 循環参照を検出した場合は現地点を採用して打ち切る。
          out.add(current);
          current = '';
          break;
        }
        visited.add(current);
        const next = String(copySourceMap.get(current) || '').trim();
        if (!next) {
          out.add(current);
          break;
        }
        current = next;
      }
    });
    return Array.from(out);
  };

  const copiedStructureGroups = collectCopiedStructureGroupsForSave();
  const manualSourceGroupIds = Array.from(new Set(
    copiedStructureGroups
      .map((entry) => String(entry?.sourceGroupId || '').trim())
      .filter((id) => id.length > 0)
  ));
  const orbitSourceGroupIds = Array.from(new Set(
    (Array.isArray(structureGenerationRuns) ? structureGenerationRuns : [])
      .filter((run) => String(run?.category || '').trim() === 'group')
      .map((run) => {
        const params = run?.params && typeof run.params === 'object' ? run.params : {};
        const explicit = String(params.groupSourceGroupId || '').trim();
        if (explicit) { return explicit; }
        const sourceKey = String(params.groupSourceKey || '').trim();
        if (sourceKey.includes('::')) {
          const keyParts = sourceKey.split('::');
          const candidate = String(keyParts[keyParts.length - 1] || '').trim();
          if (candidate) { return candidate; }
        }
        const sourceLabel = String(params.groupSourceLabel || '').trim();
        if (sourceLabel.includes('/')) {
          const labelParts = sourceLabel.split('/');
          const candidate = String(labelParts[labelParts.length - 1] || '').trim();
          if (candidate) { return candidate; }
        }
        return String(params.groupId || '').trim();
      })
      .filter((id) => id.length > 0)
  ));
  const copySourceMap = buildRuntimeGroupCopySourceMap();
  const concreteManualSourceGroupIds = resolveConcreteSourceGroupIds(manualSourceGroupIds, copySourceMap);
  const concreteOrbitSourceGroupIds = resolveConcreteSourceGroupIds(orbitSourceGroupIds, copySourceMap);
  const sourceGroupIds = Array.from(new Set([
    ...concreteManualSourceGroupIds,
    ...concreteOrbitSourceGroupIds,
  ]));
  const sourceStructureGroups = sourceGroupIds
    .map((groupId) => buildStructurePayloadForGroup(groupId))
    .filter((payload) => payload && payload?.meta?.mode !== 'group_copy_reference');
  return {
    meta: {
      version: 1,
      type: 'world_state',
      mode: 'copied_group_sources_only',
      app: 'Train_EditMode_demo',
      savedAt: new Date().toISOString(),
    },
    sourceGroupSummary: {
      manual_copy: concreteManualSourceGroupIds,
      orbit_copy: concreteOrbitSourceGroupIds,
    },
    sourceStructureGroups,
  };
}

function buildManualCopyPayload() {
  const copiedStructureGroups = collectCopiedStructureGroupsForSave();
  return {
    meta: {
      version: 1,
      type: 'manual_copy',
      app: 'Train_EditMode_demo',
      savedAt: new Date().toISOString(),
    },
    copiedStructureGroups,
  };
}

function collectWorldSaveExcludedGroupIds(groupPayload, manualCopyPayload, orbitStructurePayload) {
  const sourceGroups = Array.isArray(groupPayload?.sourceStructureGroups) ? groupPayload.sourceStructureGroups : [];
  const sourceGroupIds = sourceGroups
    .map((entry) => String(entry?.meta?.groupId || '').trim())
    .filter((id) => id.length > 0);
  const copiedGroupIds = Array.isArray(manualCopyPayload?.copiedStructureGroups)
    ? manualCopyPayload.copiedStructureGroups
      .map((entry) => String(entry?.groupId || '').trim())
      .filter((id) => id.length > 0)
    : [];
  const orbitGeneratedGroupIds = Array.from(collectRailPlacedStructureGroupIdsForSave());
  return {
    sourceGroupIds,
    copiedGroupIds,
    orbitGeneratedGroupIds,
    excludedGroupIds: new Set(sourceGroupIds),
  };
}

async function downloadWorldData() {
  let JSZipCtor = null;
  try {
    const mod = await import('https://cdn.jsdelivr.net/npm/jszip@3.10.1/+esm');
    JSZipCtor = mod?.default || mod?.JSZip || null;
  } catch (error) {
    console.warn('[world_save] jszip load failed', error);
  }
  if (!JSZipCtor) {
    alert('ZIP生成ライブラリの読み込みに失敗しました。通信状態をご確認ください。');
    return;
  }

  const groupPayload = buildWorldPayload();
  const orbitPayload = buildTrackPayloadForWorldSave();
  const orbitStructurePayload = buildStructurePayload();
  const manualCopyPayload = buildManualCopyPayload();
  const differenceSpacePayload = buildDifferenceSpacesPayload();
  const sourceSummary = groupPayload?.sourceGroupSummary && typeof groupPayload.sourceGroupSummary === 'object'
    ? groupPayload.sourceGroupSummary
    : {};
  const manualCopyGroupIds = Array.isArray(sourceSummary?.manual_copy) ? sourceSummary.manual_copy : [];
  const orbitCopyGroupIds = Array.isArray(sourceSummary?.orbit_copy) ? sourceSummary.orbit_copy : [];
  const {
    sourceGroupIds,
    copiedGroupIds,
    orbitGeneratedGroupIds,
    excludedGroupIds: singleStructureExcludedGroupIds,
  } = collectWorldSaveExcludedGroupIds(groupPayload, manualCopyPayload, orbitStructurePayload);
  const allCopiedGroupIds = Array.from(new Set([
    ...copiedGroupIds,
    ...orbitGeneratedGroupIds,
  ])).sort();
  const singleStructurePayload = buildCreateModePayload({
    includeDifferenceSpaces: false,
    materializeCopiedObjects: true,
    excludeCopiedGroupObjects: true,
    excludedGroupIds: singleStructureExcludedGroupIds,
  });
  const filteredSingleStructurePayload = filterCreateModePayloadByExcludedGroupIds(
    singleStructurePayload,
    singleStructureExcludedGroupIds,
  );
  const singleStructureSteelFrame = singleStructurePayload?.steelFrame && typeof singleStructurePayload.steelFrame === 'object'
    ? filteredSingleStructurePayload.steelFrame
    : {};
  const singleStructureGroupIds = Array.from(new Set([
    ...(Array.isArray(singleStructureSteelFrame?.segments) ? singleStructureSteelFrame.segments : [])
      .map((segment) => String(segment?.structureGroupId || '').trim())
      .filter((id) => id.length > 0),
    ...(Array.isArray(filteredSingleStructurePayload?.decorations) ? filteredSingleStructurePayload.decorations : [])
      .map((decoration) => String(decoration?.structureGroupId || '').trim())
      .filter((id) => id.length > 0),
  ])).sort();

  const zip = new JSZipCtor();
  zip.file('group.msgpack', packState(groupPayload));
  zip.file('orbit.msgpack', packState(orbitPayload));
  zip.file('orbit_structure.msgpack', packState(orbitStructurePayload));
  zip.file('manual_copy.msgpack', packState(manualCopyPayload));
  zip.file('difference_space.msgpack', packState(differenceSpacePayload));
  zip.file('single_structure.msgpack', packState(filteredSingleStructurePayload));

  const zipBlob = await zip.generateAsync({
    type: 'blob',
    compression: 'DEFLATE',
    compressionOptions: { level: 6 },
  });

  const url = URL.createObjectURL(zipBlob);
  const link = document.createElement('a');
  link.href = url;
  link.download = 'world_data.zip';
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);

  console.log('[world_save] world_data.zip saved:', {
    entries: [
      'group.msgpack',
      'orbit.msgpack',
      'orbit_structure.msgpack',
      'manual_copy.msgpack',
      'difference_space.msgpack',
      'single_structure.msgpack',
    ],
    group_count: sourceGroupIds.length,
    manual_copy: manualCopyGroupIds,
    orbit_copy: orbitCopyGroupIds,
    copied_group_ids: allCopiedGroupIds,
    manual_copied_group_ids: copiedGroupIds,
    orbit_generated_groups: orbitGeneratedGroupIds,
    single_structure_excluded_group_ids: Array.from(singleStructureExcludedGroupIds).sort(),
    single_structure_groups: singleStructureGroupIds,
    single_structure_group_count: singleStructureGroupIds.length,
  });
  alert('world_data.zip を保存しました。');
}

