function clearDifferenceSpacesForImport() {
  clearDifferencePreviewTube();
  clearDifferenceFaceHighlight();
  clearDifferenceFaceSelection();
  clearDifferenceEdgeSelection();
  clearDifferenceControlPointSelection();
  differenceSpacePlanes.forEach((mesh) => {
    if (!mesh) { return; }
    mesh.children.forEach((child) => {
      if (child?.userData?.differenceControlPoint) {
        child.geometry?.dispose?.();
        child.material?.dispose?.();
      }
    });
    if (mesh.parent) {
      mesh.parent.remove(mesh);
    }
    mesh.geometry?.dispose?.();
    if (Array.isArray(mesh.material)) {
      mesh.material.forEach((m) => m?.dispose?.());
    } else {
      mesh.material?.dispose?.();
    }
  });
  differenceSpacePlanes.length = 0;
  differenceSelectedPlane = null;
  updateDifferenceUnifyButtonState();
}

function clearDifferenceRailOperations() {
  differenceRailOperations.length = 0;
}

function buildGeometryFromSerializedSpace(rawSpace) {
  const posArr = rawSpace?.geometry?.position;
  const idxArr = rawSpace?.geometry?.index;
  if (!Array.isArray(posArr) || posArr.length < 9 || posArr.length % 3 !== 0) { return null; }
  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(posArr, 3));
  const uv = new Float32Array((posArr.length / 3) * 2);
  geometry.setAttribute('uv', new THREE.Float32BufferAttribute(uv, 2));
  if (Array.isArray(idxArr) && idxArr.length >= 3) {
    geometry.setIndex(idxArr);
  }
  geometry.computeVertexNormals();
  geometry.computeBoundingBox?.();
  geometry.computeBoundingSphere?.();
  return geometry;
}

function relinkImportedDifferenceSharedPoints(eps = differenceSharedPointLinkEpsilon) {
  const points = [];
  differenceSpacePlanes.forEach((mesh) => {
    mesh?.children?.forEach((child) => {
      if (!child?.userData?.differenceControlPoint || !child.parent) { return; }
      points.push(child);
    });
  });
  for (let i = 0; i < points.length; i += 1) {
    const a = points[i];
    const aw = a.getWorldPosition(new THREE.Vector3());
    for (let j = i + 1; j < points.length; j += 1) {
      const b = points[j];
      if (a.parent === b.parent) { continue; }
      const bw = b.getWorldPosition(new THREE.Vector3());
      if (aw.distanceToSquared(bw) <= eps * eps) {
        addDifferenceSharedPointLink(a, b);
      }
    }
  }
}

function applyCreateModePayload(payload) {
  if (!payload || typeof payload !== 'object') {
    throw new Error('map_data の形式が不正です。');
  }
  clearCreateHistory();
  clearDifferenceHistory();
  clearDifferenceRailOperations();
  stopAllConfiguredTrains();
  structureGroupSourceIndex.clear();
  structureGroupSourceById.clear();
  const baseGuideGrid = (payload?.baseGuideGrid && typeof payload.baseGuideGrid === 'object')
    ? payload.baseGuideGrid
    : null;
  const guideGridStates = Array.isArray(payload?.guideAddGrids) ? payload.guideAddGrids : [];
  const steelFrameState = (payload?.steelFrame && typeof payload.steelFrame === 'object')
    ? payload.steelFrame
    : null;
  const decorationStates = Array.isArray(payload?.decorations) ? payload.decorations : [];
  applyBaseGuideGridState(baseGuideGrid);
  clearGuideAddGridsForImport();
  const mirrorGuideStates = [];
  const nonMirrorGuideStates = [];
  guideGridStates.forEach((state) => {
    const isMirrorGrid = Boolean(state?.guideMirrorLocked) && !Boolean(state?.guideMillerInfluencePlane);
    if (isMirrorGrid) {
      mirrorGuideStates.push(state);
    } else {
      nonMirrorGuideStates.push(state);
    }
  });
  const loadedGuideGrids = [];
  nonMirrorGuideStates.forEach((state) => {
    const grid = addGuideGridFromState(state);
    loadedGuideGrids.push(grid || null);
  });
  clearSteelFrameForImport();
  const keyToGrid = new Map();
  keyToGrid.set('base', AddPointGuideGrid);
  nonMirrorGuideStates.forEach((state, idx) => {
    const key = typeof state?.saveKey === 'string' ? state.saveKey : `g${idx}`;
    const grid = loadedGuideGrids[idx] || null;
    if (key && grid) {
      keyToGrid.set(key, grid);
    }
  });
  guideAddGrids.forEach((grid) => {
    const key = typeof grid?.userData?.saveKey === 'string' ? grid.userData.saveKey : null;
    if (key && !keyToGrid.has(key)) {
      keyToGrid.set(key, grid);
    }
  });
  restoreSteelFrameState(steelFrameState, keyToGrid);
  clearDecorationsForImport();
  restoreDecorationsState(decorationStates, keyToGrid);
  restoreCopiedStructureGroupsFromSave(payload?.copiedStructureGroups);
  syncStructureGroupSequenceFromExisting();
  rebuildMirrorFromStatesRuntime({
    mirrorStates: mirrorGuideStates,
    maxPasses: 6,
    tryCreateMirrorFromState: (state) => createGuideMirrorGridFromStateLink(state, keyToGrid),
  });
  rebuildMirrorStateOnLoad(keyToGrid, 4);
  refreshSteelFrameMirrorPreviews();
  changeAngleGridTarget = getLastEditableGuideGrid();
  const spaces = Array.isArray(payload.differenceSpaces) ? payload.differenceSpaces : [];
  restoreDifferenceSpacesFromPayload(payload, { clearExisting: true, applyToCity: true });
  trainRunConfigs = Array.isArray(payload?.trainRunConfigs) && payload.trainRunConfigs.length > 0
    ? payload.trainRunConfigs.map((config) => normalizeTrainRunConfig(config))
    : [structuredClone(DEFAULT_TRAIN_RUN_CONFIG)];

  const mode = payload.mode && typeof payload.mode === 'object' ? payload.mode : {};
  editObject = typeof mode.editObject === 'string' ? mode.editObject : editObject;
  objectEditMode = typeof mode.objectEditMode === 'string' ? mode.objectEditMode : objectEditMode;
  search_object = Boolean(mode.searchObject);
  move_direction_y = Boolean(mode.moveDirectionY);
  differenceSpaceModeActive = Boolean(mode.differenceSpaceModeActive);
  differenceSpaceTransformMode = typeof mode.differenceSpaceTransformMode === 'string'
    ? mode.differenceSpaceTransformMode
    : differenceSpaceTransformMode;
  differenceShapeType = typeof mode.differenceShapeType === 'string' ? mode.differenceShapeType : differenceShapeType;
  differencePathType = typeof mode.differencePathType === 'string' ? mode.differencePathType : differencePathType;
  if (Array.isArray(mode.differenceLineTrackNames)) {
    differenceLineTrackNames = normalizeDifferenceLineTrackNames(mode.differenceLineTrackNames);
  } else if (typeof mode.differenceLineTrackName === 'string') {
    const legacy = String(mode.differenceLineTrackName).trim();
    differenceLineTrackNames = (legacy && legacy.toLowerCase() !== 'all')
      ? normalizeDifferenceLineTrackNames([legacy])
      : [];
  }
  if (Number.isFinite(Number(mode.differenceLineBandHeight))) {
    differenceLineBandHeight = Math.max(0.2, Number(mode.differenceLineBandHeight));
  }
  if (differenceShapeSelect) {
    differenceShapeSelect.value = differenceShapeType;
  }
  if (differencePathSelect) {
    differencePathSelect.value = differencePathType;
  }
  if (differenceLineHeightInput) {
    differenceLineHeightInput.value = String(differenceLineBandHeight);
  }
  if (differenceLineSelect) {
    setDifferenceLineOptions();
  }
  targetObjects = differenceSpacePlanes.filter((m) => m?.parent);
  setMeshListOpacity(targetObjects, 1);
  refreshDifferencePreview();
  updateDifferenceStatus(`map_data 読込完了: 空間 ${differenceSpacePlanes.length} 件 / ガイド ${guideAddGrids.length} 件`);
  updateDifferenceUnifyButtonState();

  if (payload.uiState && typeof payload.uiState === 'object') {
    try {
      localStorage.setItem(UI_STATE_STORAGE_KEY, JSON.stringify(payload.uiState));
    } catch (err) {
      console.warn('failed to store uiState', err);
    }
  }
  setRailConstructionGroupOptions();
  updateGroupModePanelUI();
  updateGroundOpacityButtonState();
  syncTrainPanelFromConfig();
  applyAllConfiguredTrains();
}

async function loadRuntimeMapGlbFromPublicUpload(arrayBuffer, fileName = 'public-upload.glb', kind = 'ct') {
  const loader = new GLTFLoader();
  const gltf = await new Promise((resolve, reject) => {
    loader.parse(
      arrayBuffer,
      '',
      (parsed) => resolve(parsed),
      (error) => reject(error || new Error('glb parse failed'))
    );
  });

  const root = gltf?.scene || gltf?.scenes?.[0] || null;
  if (!root) {
    throw new Error('glb にシーンがありません。');
  }

  const objectName = `__public_runtime_${kind}_glb__`;
  const previous = scene.getObjectByName(objectName);
  if (previous?.parent) {
    previous.parent.remove(previous);
  }

  const alignRootVisualCenterXzToOrigin = (targetRoot) => {
    if (!targetRoot) { return; }
    targetRoot.updateMatrixWorld(true);
    const targetBox = new THREE.Box3().setFromObject(targetRoot);
    if (targetBox.isEmpty()) { return; }
    const targetCenter = targetBox.getCenter(new THREE.Vector3());
    targetRoot.position.x -= targetCenter.x;
    targetRoot.position.z -= targetCenter.z;
    targetRoot.updateMatrixWorld(true);
  };

  const box = new THREE.Box3().setFromObject(root);
  const size = box.getSize(new THREE.Vector3());

  const maxDim = Math.max(size.x, size.y, size.z);
  if (maxDim > 10000) {
    root.scale.setScalar(0.001);
  }
  if (kind === 'ct') {
    root.rotation.y = 0;
    const currentY = root.position.y;
    root.position.set(0, currentY, 0);
    root.scale.multiplyScalar(WORLD_SCALE);
    alignRootVisualCenterXzToOrigin(root);
  }

  root.name = objectName;
  scene.add(root);
}

