async function loadRuntimeMapFromPublicUpload() {
  const searchParams = new URLSearchParams(window.location.search);
  if (!IS_RUNTIME_LOCAL_VIEW) {
    return false;
  }

  const loadRuntimeMapFallbackFromFolder = async () => {
    const manifestUrl = '../map_data/manifest.json';
    const manifestResponse = await fetch(manifestUrl, { cache: 'no-store' });
    if (!manifestResponse.ok) {
      throw new Error('map_data/manifest.json が見つかりません。');
    }
    const manifest = await manifestResponse.json();
    const manifestFiles = Array.isArray(manifest?.files) ? manifest.files : [];
    const loadedFiles = [];
    for (const entry of manifestFiles) {
      const name = String(entry?.name || '').trim();
      const kind = String(entry?.kind || 'ct').trim() || 'ct';
      if (!name) { continue; }
      const fileUrl = `../map_data/${encodeURIComponent(name)}`;
      const response = await fetch(fileUrl, { cache: 'no-store' });
      if (!response.ok) {
        console.warn('[map_data fallback] file fetch failed', { fileUrl, status: response.status });
        continue;
      }
      const buffer = await response.arrayBuffer();
      loadedFiles.push([kind, {
        name,
        size: buffer.byteLength,
        buffer,
      }]);
    }
    return loadedFiles;
  };

  const record = await readRuntimeMapRecord().catch(() => null);
  const runtimeFiles = record?.files && typeof record.files === 'object'
    ? record.files
    : { ct: record };
  let fileEntries = Object.entries(runtimeFiles)
    .flatMap(([kind, file]) => {
      if (kind === 'tr' && Array.isArray(file)) {
        return file
          .filter((entry) => entry && typeof entry === 'object' && entry.buffer)
          .map((entry) => [kind, entry]);
      }
      return (file && typeof file === 'object' && file.buffer) ? [[kind, file]] : [];
    });
  const runtimeKindPriority = { tr: 0, ct: 1, st: 2 };
  fileEntries.sort((a, b) => {
    const aPriority = runtimeKindPriority[String(a?.[0] || '')] ?? 99;
    const bPriority = runtimeKindPriority[String(b?.[0] || '')] ?? 99;
    return aPriority - bPriority;
  });
  if (fileEntries.length < 1) {
    fileEntries = await loadRuntimeMapFallbackFromFolder();
    fileEntries.sort((a, b) => {
      const aPriority = runtimeKindPriority[String(a?.[0] || '')] ?? 99;
      const bPriority = runtimeKindPriority[String(b?.[0] || '')] ?? 99;
      return aPriority - bPriority;
    });
  }
  if (fileEntries.length < 1) {
    throw new Error('public.html で選択されたマップファイルも map_data フォルダーも見つかりません。');
  }

  const loadedNames = [];
  const classifyRuntimeArchiveEntry = (entryName, payload, fallbackKind = 'ct') => {
    const lower = String(entryName || '').trim().toLowerCase();
    if (lower.startsWith('st')) { return 'st'; }
    if (lower.startsWith('ct')) { return 'ct'; }
    if (lower.startsWith('tr')) { return 'tr'; }
    if (lower.includes('create_mode_state') || lower.includes('single_structure')) { return 'ct'; }
    if (lower.includes('orbit_structure')) { return 'st'; }

    const mode = String(payload?.meta?.mode || '').trim();
    const hasMapFeatures =
      Array.isArray(payload?.guideAddGrids) && payload.guideAddGrids.length > 0
      || Array.isArray(payload?.differenceSpaces) && payload.differenceSpaces.length > 0
      || Array.isArray(payload?.differenceRailOperations) && payload.differenceRailOperations.length > 0
      || (payload?.baseGuideGrid && typeof payload.baseGuideGrid === 'object')
      || (payload?.uiState && typeof payload.uiState === 'object');
    const hasPins = Array.isArray(payload?.pins) && payload.pins.length > 0;
    const hasStructureRuns = Array.isArray(payload?.generationRuns) && payload.generationRuns.length > 0;
    const hasCopiedRefs = Array.isArray(payload?.copiedStructureGroups) && payload.copiedStructureGroups.length > 0;
    const hasGroupObjects =
      Array.isArray(payload?.steelFrame?.segments) && payload.steelFrame.segments.length > 0
      || Array.isArray(payload?.decorations) && payload.decorations.length > 0
      || hasCopiedRefs;

    if (hasMapFeatures) {
      return 'ct';
    }
    if (mode.startsWith('group_') || hasStructureRuns || hasPins || hasGroupObjects) {
      return 'st';
    }
    return fallbackKind;
  };
  const applyRuntimeStructurePayload = (payload, runtimeName) => {
    const sourceTag = String(runtimeName).replace(/\.(json|msgpack|mpk|zip)$/i, '') || 'runtime_structure';
    const mode = String(payload?.meta?.mode || '').trim();
    if (mode === 'copied_group_sources_only' && Array.isArray(payload?.sourceStructureGroups)) {
      return;
    }
    if (String(payload?.meta?.type || '').trim() === 'manual_copy' && Array.isArray(payload?.copiedStructureGroups)) {
      return;
    }
    const hasStructurePins = Array.isArray(payload?.pins) && payload.pins.length > 0;
    const hasStructureRuns = Array.isArray(payload?.generationRuns) && payload.generationRuns.length > 0;
    const hasCopiedRefs = Array.isArray(payload?.copiedStructureGroups) && payload.copiedStructureGroups.length > 0;
    const hasGroupObjects =
      Array.isArray(payload?.steelFrame?.segments) && payload.steelFrame.segments.length > 0
      || Array.isArray(payload?.decorations) && payload.decorations.length > 0
      || hasCopiedRefs;
    if (hasGroupObjects) {
      appendCreateModeGroupsPayload(payload, { sourceTag });
    }
    if (hasStructurePins || hasStructureRuns) {
      applyStructureDataPayload(payload);
    }
  };
  for (const [kind, runtimeFile] of fileEntries) {
    const runtimeName = String(runtimeFile?.name || 'public-upload');
    loadedNames.push(runtimeName);
    if (kind === 'tr') {
      if (/\.glb$/i.test(runtimeName)) {
        try {
          await registerRuntimeTrainModelFromArrayBuffer(runtimeFile.buffer, runtimeName);
        } catch (err) {
          console.warn('[public_upload][train] register failed', { name: runtimeName, err });
        }
      } else {
        console.warn('[public_upload][train] unsupported file type', { name: runtimeName });
      }
      continue;
    }
    if (/\.glb$/i.test(runtimeName)) {
      await loadRuntimeMapGlbFromPublicUpload(runtimeFile.buffer, runtimeName, kind);
      continue;
    }
    const bytes = new Uint8Array(runtimeFile.buffer);
    if (/\.zip$/i.test(runtimeName)) {
      const archiveRows = await readMapDataArchiveBytes(bytes, {
        name: runtimeName,
        size: Number(runtimeFile?.size) || bytes.byteLength,
      });
      console.info('[public_upload][zip] archive entries', archiveRows.map((row) => ({
        name: row?.name,
        mode: String(row?.payload?.meta?.mode || '').trim(),
        hasPins: Array.isArray(row?.payload?.pins) ? row.payload.pins.length : -1,
        hasRuns: Array.isArray(row?.payload?.generationRuns) ? row.payload.generationRuns.length : -1,
        steelSegments: Array.isArray(row?.payload?.steelFrame?.segments) ? row.payload.steelFrame.segments.length : -1,
        decorations: Array.isArray(row?.payload?.decorations) ? row.payload.decorations.length : -1,
        copiedGroups: Array.isArray(row?.payload?.copiedStructureGroups) ? row.payload.copiedStructureGroups.length : -1,
      })));
      const ctRows = [];
      const sourceGroupPayloadRows = [];
      const baseRows = [];
      const copyRows = [];
      const pinRows = [];
      const manualCopyRows = [];
      archiveRows.forEach((row) => {
        const payload = row?.payload;
        const mode = String(payload?.meta?.mode || '').trim();
        const type = String(payload?.meta?.type || '').trim();
        if (mode === 'copied_group_sources_only' && Array.isArray(payload?.sourceStructureGroups)) {
          console.info('[public_upload][group_msgpack] discovered source groups', {
            name: row?.name,
            count: payload.sourceStructureGroups.length,
          });
          sourceGroupPayloadRows.push(...payload.sourceStructureGroups.map((groupPayload, index) => {
            const sourceTag = String(groupPayload?.meta?.groupId || '').trim() || `runtime_group_${index + 1}`;
            const groupMode = String(groupPayload?.meta?.mode || '').trim();
            const hasCopiedRefs = Array.isArray(groupPayload?.copiedStructureGroups) && groupPayload.copiedStructureGroups.length > 0;
            return {
              url: `${row?.name || runtimeName}::${sourceTag}`,
              payload: groupPayload,
              sourceTag,
              isCopyReference: groupMode === 'group_copy_reference' || hasCopiedRefs,
            };
          }));
          return;
        }
        if (type === 'manual_copy' && Array.isArray(payload?.copiedStructureGroups)) {
          console.info('[public_upload][manual_copy] discovered copied groups', {
            name: row?.name,
            count: payload.copiedStructureGroups.length,
          });
          manualCopyRows.push(row);
          return;
        }
        const entryKind = classifyRuntimeArchiveEntry(row?.name, payload, kind);
        console.info('[public_upload][zip] classify entry', {
          name: row?.name,
          entryKind,
          fallbackKind: kind,
          mode: String(payload?.meta?.mode || '').trim(),
        });
        if (entryKind === 'ct') {
          ctRows.push(row);
          return;
        }
        if (entryKind !== 'st') {
          return;
        }
        const hasCopiedRefs = Array.isArray(payload?.copiedStructureGroups) && payload.copiedStructureGroups.length > 0;
        const hasGroupObjects =
          Array.isArray(payload?.steelFrame?.segments) && payload.steelFrame.segments.length > 0
          || Array.isArray(payload?.decorations) && payload.decorations.length > 0
          || hasCopiedRefs;
        const hasPins = Array.isArray(payload?.pins) && payload.pins.length > 0;
        const hasRuns = Array.isArray(payload?.generationRuns) && payload.generationRuns.length > 0;
        if (hasGroupObjects) {
          if (mode === 'group_copy_reference' || hasCopiedRefs) {
            copyRows.push(row);
          } else {
            baseRows.push(row);
          }
        }
        if (hasPins || hasRuns) {
          console.info('[public_upload][pins] queued runtime structure payload', {
            name: row?.name,
            pinCount: hasPins ? payload.pins.length : 0,
            runCount: hasRuns ? payload.generationRuns.length : 0,
          });
          pinRows.push(row);
        }
      });
      console.info('[public_upload][zip] restore queue summary', {
        ctRows: ctRows.length,
        sourceGroupPayloadRows: sourceGroupPayloadRows.length,
        structureBaseRows: baseRows.length,
        structureCopyRows: copyRows.length,
        manualCopyRows: manualCopyRows.length,
        pinRows: pinRows.length,
      });
      ctRows.forEach((row) => {
        try {
          const payload = row?.payload && typeof row.payload === 'object' ? row.payload : {};
          const steelFrame = payload?.steelFrame && typeof payload.steelFrame === 'object'
            ? payload.steelFrame
            : {};
          console.info('[public_upload][ct] applying payload start', {
            name: row?.name,
            mode: payload?.meta?.mode || payload?.mode || '',
            guideAddGrids: Array.isArray(payload?.guideAddGrids) ? payload.guideAddGrids.length : 0,
            differenceSpaces: Array.isArray(payload?.differenceSpaces) ? payload.differenceSpaces.length : 0,
            differenceRailOperations: Array.isArray(payload?.differenceRailOperations) ? payload.differenceRailOperations.length : 0,
            steelFramePoints: Array.isArray(steelFrame?.points) ? steelFrame.points.length : 0,
            steelFrameSegments: Array.isArray(steelFrame?.segments) ? steelFrame.segments.length : 0,
            copiedInstances: Array.isArray(steelFrame?.copiedInstances) ? steelFrame.copiedInstances.length : 0,
            decorations: Array.isArray(payload?.decorations) ? payload.decorations.length : 0,
            copiedStructureGroups: Array.isArray(payload?.copiedStructureGroups) ? payload.copiedStructureGroups.length : 0,
          });
          if (payloadHasOnlyDifferenceSpaces(payload)) {
            restoreDifferenceSpacesFromPayload(payload, { clearExisting: true, applyToCity: true });
          } else {
            applyCreateModePayload(payload);
          }
          console.info('[public_upload][ct] applying payload done', {
            name: row?.name,
          });
        } catch (err) {
          console.warn('[public_upload][ct] applying payload failed', {
            name: row?.name,
            err,
          });
        }
      });
      if (sourceGroupPayloadRows.length > 0) {
        console.info('[public_upload][group_msgpack] restoring source groups start', {
          count: sourceGroupPayloadRows.length,
        });
        await applyStructureGroupSourceRows(sourceGroupPayloadRows, {
          logLabel: '[public_upload][group_msgpack]',
          updateStatus: false,
        });
        console.info('[public_upload][group_msgpack] restoring source groups done', {
          count: sourceGroupPayloadRows.length,
        });
      }
      const structureGroupRows = [...baseRows, ...copyRows].map((row) => ({
        url: row?.name || runtimeName,
        payload: row?.payload,
        sourceTag: String(row?.name || runtimeName).replace(/\.(json|msgpack|mpk|zip)$/i, '') || 'runtime_structure',
        isCopyReference: copyRows.includes(row),
      }));
      if (structureGroupRows.length > 0) {
        console.info('[public_upload][structure_group] restoring rows start', {
          count: structureGroupRows.length,
        });
        await applyStructureGroupSourceRows(structureGroupRows, {
          logLabel: '[public_upload][structure_group]',
          updateStatus: false,
        });
        console.info('[public_upload][structure_group] restoring rows done', {
          count: structureGroupRows.length,
        });
      }
      manualCopyRows.forEach((row) => {
        const copiedGroups = Array.isArray(row?.payload?.copiedStructureGroups) ? row.payload.copiedStructureGroups : [];
        if (copiedGroups.length > 0) {
          console.info('[public_upload][manual_copy] restoring copied groups', {
            name: row?.name,
            count: copiedGroups.length,
          });
          restoreCopiedStructureGroupsFromSave(copiedGroups);
        }
      });
      pinRows.forEach((row) => {
        console.info('[public_upload][pins] applying queued runtime structure payload', {
          name: row?.name,
        });
        applyRuntimeStructurePayload(row.payload, row.name || runtimeName);
      });
      continue;
    }
    const payload = await readMapDataBytes(bytes, {
      name: runtimeName,
      size: Number(runtimeFile?.size) || bytes.byteLength,
    });
    if (kind === 'st') {
      const mode = String(payload?.meta?.mode || '').trim();
      const type = String(payload?.meta?.type || '').trim();
      if (mode === 'copied_group_sources_only' && Array.isArray(payload?.sourceStructureGroups)) {
        await applyStructureGroupSourceRows(
          payload.sourceStructureGroups.map((groupPayload, index) => {
            const sourceTag = String(groupPayload?.meta?.groupId || '').trim() || `runtime_group_${index + 1}`;
            const groupMode = String(groupPayload?.meta?.mode || '').trim();
            const hasCopiedRefs = Array.isArray(groupPayload?.copiedStructureGroups) && groupPayload.copiedStructureGroups.length > 0;
            return {
              url: `${runtimeName}::${sourceTag}`,
              payload: groupPayload,
              sourceTag,
              isCopyReference: groupMode === 'group_copy_reference' || hasCopiedRefs,
            };
          }),
          {
            logLabel: '[public_upload][group_msgpack]',
            updateStatus: false,
          }
        );
        continue;
      }
      if (type === 'manual_copy' && Array.isArray(payload?.copiedStructureGroups)) {
        restoreCopiedStructureGroupsFromSave(payload.copiedStructureGroups);
        continue;
      }
      const hasCopiedRefs = Array.isArray(payload?.copiedStructureGroups) && payload.copiedStructureGroups.length > 0;
      const hasGroupObjects =
        Array.isArray(payload?.steelFrame?.segments) && payload.steelFrame.segments.length > 0
        || Array.isArray(payload?.decorations) && payload.decorations.length > 0
        || hasCopiedRefs;
      if (hasGroupObjects) {
        await applyStructureGroupSourceRows([{
          url: runtimeName,
          payload,
          sourceTag: String(runtimeName).replace(/\.(json|msgpack|mpk|zip)$/i, '') || 'runtime_structure',
          isCopyReference: String(payload?.meta?.mode || '').trim() === 'group_copy_reference' || hasCopiedRefs,
        }], {
          logLabel: '[public_upload][structure_group]',
          updateStatus: false,
        });
      }
      applyRuntimeStructurePayload(payload, runtimeName);
      continue;
    }
    if (kind !== 'ct') {
      continue;
    }
    if (payloadHasOnlyDifferenceSpaces(payload)) {
      restoreDifferenceSpacesFromPayload(payload, { clearExisting: true, applyToCity: true });
    } else {
      applyCreateModePayload(payload);
    }
  }

  const runtimeLabel = IS_EDIT_RUNTIME_LOCAL_VIEW ? 'edit object' : 'public object';
  const statusText = `${runtimeLabel} 読込完了: ${loadedNames.join(', ')}`;
  setMapLoadStatusText(statusText);
  if (railConstructionStatus) { railConstructionStatus.textContent = statusText; }
  updateDifferenceStatus(statusText);
  updateGroundOpacityButtonState();
  if (IS_PUBLIC_RUNTIME_LOCAL_VIEW) {
    activatePublicRuntimeObjectViewMode();
    publicRuntimeMapCleanupPending = true;
  }
  return true;
}

function buildExistingGuideGridKeyMap() {
  const keyToGrid = new Map();
  keyToGrid.set('base', AddPointGuideGrid);
  guideAddGrids.forEach((grid) => {
    const key = typeof grid?.userData?.saveKey === 'string' ? grid.userData.saveKey : null;
    if (key && !keyToGrid.has(key)) {
      keyToGrid.set(key, grid);
    }
  });
  return keyToGrid;
}

function createStructureGroupIdRemapper() {
  const existingIds = new Set(collectStructureGroupIds());
  const idMap = new Map();
  let remappedCount = 0;

  const reserve = (rawId) => {
    const src = String(rawId || '').trim();
    if (!src) { return ''; }
    if (idMap.has(src)) {
      return idMap.get(src);
    }

    let candidate = src;
    if (existingIds.has(candidate)) {
      // 既存IDと衝突する場合のみ改名。
      const fallbackBase = /^structure_group_\d+$/.test(src) ? 'structure_group' : src;
      let n = 2;
      while (existingIds.has(candidate)) {
        if (fallbackBase === 'structure_group') {
          candidate = `structure_group_${structureGroupSeq}`;
          structureGroupSeq += 1;
        } else {
          candidate = `${fallbackBase}__${n}`;
          n += 1;
        }
      }
    }

    existingIds.add(candidate);
    idMap.set(src, candidate);
    if (candidate !== src) {
      remappedCount += 1;
    }
    return candidate;
  };

  return {
    reserve,
    getEntries: () => Array.from(idMap.entries()).map(([sourceGroupId, remappedGroupId]) => ({
      sourceGroupId,
      remappedGroupId,
    })),
    getRemappedCount: () => remappedCount,
  };
}

function remapAllStructureGroupIdsForAppend(steelFrameState, decorationStates) {
  const remapper = createStructureGroupIdRemapper();

  const mappedSteelFrameState = steelFrameState && typeof steelFrameState === 'object'
    ? {
      points: Array.isArray(steelFrameState.points) ? steelFrameState.points.map((point) => ({ ...point })) : [],
      segments: Array.isArray(steelFrameState.segments)
        ? steelFrameState.segments.map((seg) => {
          const next = { ...seg };
          const gid = String(seg?.structureGroupId || '').trim();
          if (gid) {
            next.structureGroupId = remapper.reserve(gid);
          }
          return next;
        })
        : [],
    }
    : null;

  const mappedDecorationStates = Array.isArray(decorationStates)
    ? decorationStates.map((state) => {
      const next = { ...state };
      const gid = String(state?.structureGroupId || '').trim();
      if (gid) {
        next.structureGroupId = remapper.reserve(gid);
      }
      return next;
    })
    : [];

  return {
    steelFrameState: mappedSteelFrameState,
    decorationStates: mappedDecorationStates,
    remappedCount: remapper.getRemappedCount(),
    remappedEntries: remapper.getEntries(),
  };
}

function appendCreateModePayload(payload, options = {}) {
  if (!payload || typeof payload !== 'object') {
    throw new Error('map_data の形式が不正です。');
  }
  const sourceTag = normalizeStructureGroupSourceTag(options?.sourceTag || 'runtime');
  const guideGridStates = Array.isArray(payload?.guideAddGrids) ? payload.guideAddGrids : [];
  const copiedStructureGroupsRaw = Array.isArray(payload?.copiedStructureGroups) ? payload.copiedStructureGroups : [];
  const steelFrameStateRaw = (payload?.steelFrame && typeof payload.steelFrame === 'object')
    ? payload.steelFrame
    : null;
  const decorationStatesRaw = Array.isArray(payload?.decorations) ? payload.decorations : [];
  const mirrorGuideStates = [];
  const nonMirrorGuideStates = [];
  guideGridStates.forEach((state) => {
    const isMirrorGrid = Boolean(state?.guideMirrorLocked) && !Boolean(state?.guideMillerInfluencePlane);
    if (isMirrorGrid) {
      mirrorGuideStates.push(state);
    } else {
      nonMirrorGuideStates.push(state);
    }
  });

  syncStructureGroupSequenceFromExisting();
  const remapped = remapAllStructureGroupIdsForAppend(steelFrameStateRaw, decorationStatesRaw);
  const steelFrameState = remapped.steelFrameState;
  const decorationStates = remapped.decorationStates;
  const remapSourceIdMap = new Map((remapped.remappedEntries || []).map((entry) => [String(entry?.sourceGroupId || ''), String(entry?.remappedGroupId || '')]));
  const reservedGroupIds = new Set(collectStructureGroupIds());
  (remapped.remappedEntries || []).forEach((entry) => {
    const id = String(entry?.remappedGroupId || '').trim();
    if (id) { reservedGroupIds.add(id); }
  });
  const copiedStructureGroups = copiedStructureGroupsRaw.map((entry) => {
    const sourceId = String(entry?.sourceGroupId || '').trim();
    const mapped = remapSourceIdMap.get(sourceId) || sourceId;
    const requestedGroupId = String(entry?.groupId || '').trim();
    let groupId = requestedGroupId;
    if (groupId) {
      if (!reservedGroupIds.has(groupId)) {
        reservedGroupIds.add(groupId);
      } else {
        let n = 2;
        let candidate = `${groupId}__${n}`;
        while (reservedGroupIds.has(candidate)) {
          n += 1;
          candidate = `${groupId}__${n}`;
        }
        groupId = candidate;
        reservedGroupIds.add(groupId);
      }
    }
    return {
      ...entry,
      sourceGroupId: mapped,
      groupId: groupId || null,
    };
  });

  const loadedGuideGrids = [];
  nonMirrorGuideStates.forEach((state) => {
    const grid = addGuideGridFromState(state);
    loadedGuideGrids.push(grid || null);
  });
  const keyToGrid = new Map();
  keyToGrid.set('base', AddPointGuideGrid);
  nonMirrorGuideStates.forEach((state, idx) => {
    const key = typeof state?.saveKey === 'string' ? state.saveKey : `g${idx}`;
    const grid = loadedGuideGrids[idx] || null;
    if (key && grid) {
      keyToGrid.set(key, grid);
    }
  });
  guideAddGrids.forEach((grid) => {
    const key = typeof grid?.userData?.saveKey === 'string' ? grid.userData.saveKey : null;
    if (key && !keyToGrid.has(key)) {
      keyToGrid.set(key, grid);
    }
  });

  restoreSteelFrameState(steelFrameState, keyToGrid);
  restoreDecorationsState(decorationStates, keyToGrid);
  restoreCopiedStructureGroupsFromSave(copiedStructureGroups);
  registerStructureGroupSourceMappings(remapped.remappedEntries, sourceTag);
  syncStructureGroupSequenceFromExisting();

  rebuildMirrorFromStatesRuntime({
    mirrorStates: mirrorGuideStates,
    maxPasses: 6,
    tryCreateMirrorFromState: (state) => createGuideMirrorGridFromStateLink(state, keyToGrid),
  });
  rebuildMirrorStateOnLoad(keyToGrid, 4);
  refreshSteelFrameMirrorPreviews();
  changeAngleGridTarget = getLastEditableGuideGrid();
  const spaces = Array.isArray(payload.differenceSpaces) ? payload.differenceSpaces : [];
  restoreDifferenceSpacesFromPayload(payload, { clearExisting: false, applyToCity: true });

  setRailConstructionGroupOptions();
  updateGroupModePanelUI();

  return {
    guideCount: loadedGuideGrids.filter(Boolean).length,
    segmentCount: Array.isArray(steelFrameState?.segments) ? steelFrameState.segments.length : 0,
    decorationCount: decorationStates.length,
    spaceCount: spaces.length,
    remappedGroupCount: remapped.remappedCount || 0,
  };
}

function hasAnyGroupTagOnSegmentState(state) {
  const structureGroupId = String(state?.structureGroupId || '').trim();
  const copyGroupId = String(state?.steelFrameCopyGroupId || '').trim();
  return Boolean(structureGroupId || copyGroupId || Boolean(state?.steelFrameCopiedObject));
}

function filterGroupedSteelFrameState(payloadSteelFrame) {
  if (!payloadSteelFrame || typeof payloadSteelFrame !== 'object') { return null; }
  const allPoints = Array.isArray(payloadSteelFrame.points) ? payloadSteelFrame.points : [];
  const allSegments = Array.isArray(payloadSteelFrame.segments) ? payloadSteelFrame.segments : [];
  const groupedSegments = allSegments.filter((state) => hasAnyGroupTagOnSegmentState(state));
  if (groupedSegments.length < 1) { return null; }
  const usedPointKeys = new Set();
  groupedSegments.forEach((seg) => {
    const keys = Array.isArray(seg?.pointKeys) ? seg.pointKeys : [];
    keys.forEach((key) => {
      const k = String(key || '').trim();
      if (k) { usedPointKeys.add(k); }
    });
  });
  const groupedPoints = allPoints.filter((point) => {
    const key = String(point?.key || '').trim();
    return Boolean(key && usedPointKeys.has(key));
  });
  return {
    points: groupedPoints,
    segments: groupedSegments,
  };
}

function filterGroupedDecorationStates(payloadDecorations) {
  const states = Array.isArray(payloadDecorations) ? payloadDecorations : [];
  return states.filter((state) => {
    const structureGroupId = String(state?.structureGroupId || '').trim();
    return Boolean(structureGroupId);
  });
}

function remapStructureGroupIdsForAppend(steelFrameState, decorationStates) {
  const remapper = createStructureGroupIdRemapper();

  const mappedSteelFrameState = steelFrameState && typeof steelFrameState === 'object'
    ? {
      points: Array.isArray(steelFrameState.points) ? steelFrameState.points.map((point) => ({ ...point })) : [],
      segments: Array.isArray(steelFrameState.segments)
        ? steelFrameState.segments.map((seg) => {
          const next = { ...seg };
          const gid = String(seg?.structureGroupId || '').trim();
          if (gid) {
            next.structureGroupId = remapper.reserve(gid);
          }
          return next;
        })
        : [],
    }
    : null;

  const mappedDecorationStates = Array.isArray(decorationStates)
    ? decorationStates.map((state) => {
      const next = { ...state };
      const gid = String(state?.structureGroupId || '').trim();
      if (gid) {
        next.structureGroupId = remapper.reserve(gid);
      }
      return next;
    })
    : [];

  return {
    steelFrameState: mappedSteelFrameState,
    decorationStates: mappedDecorationStates,
    remappedCount: remapper.getRemappedCount(),
    remappedEntries: remapper.getEntries(),
  };
}

function hydrateStandaloneStructureGroupPayload(payload) {
  if (!payload || typeof payload !== 'object') {
    return {
      steelFrame: null,
      decorations: [],
    };
  }
  const groupId = String(payload?.meta?.groupId || '').trim();
  const rawSteelFrame = payload?.steelFrame && typeof payload.steelFrame === 'object'
    ? payload.steelFrame
    : null;
  const rawPoints = Array.isArray(rawSteelFrame?.points) ? rawSteelFrame.points : [];
  const rawSegments = Array.isArray(rawSteelFrame?.segments) ? rawSteelFrame.segments : [];
  const steelFrame = (rawPoints.length > 0 || rawSegments.length > 0)
    ? {
      points: rawPoints.map((point) => ({ ...point })),
      segments: rawSegments.map((segment) => ({
        ...segment,
        structureGroupId: String(segment?.structureGroupId || '').trim() || groupId || null,
      })),
    }
    : null;
  const decorations = Array.isArray(payload?.decorations)
    ? payload.decorations.map((decoration) => ({
      ...decoration,
      structureGroupId: String(decoration?.structureGroupId || '').trim() || groupId || null,
    }))
    : [];
  const rotation = parseSavedGroupRotationAngles(payload?.meta);
  return { steelFrame, decorations, rotation };
}

function appendCreateModeGroupsPayload(payload, options = {}) {
  if (!payload || typeof payload !== 'object') {
    throw new Error('map_data の形式が不正です。');
  }
  const sourceTag = normalizeStructureGroupSourceTag(options?.sourceTag || 'runtime');
  const copiedStructureGroupsRaw = Array.isArray(payload?.copiedStructureGroups) ? payload.copiedStructureGroups : [];
  const payloadMode = String(payload?.meta?.mode || '').trim();
  syncStructureGroupSequenceFromExisting();
  const guideGridStates = Array.isArray(payload?.guideAddGrids) ? payload.guideAddGrids : [];
  const mirrorGuideStates = [];
  const nonMirrorGuideStates = [];
  guideGridStates.forEach((state) => {
    const isMirrorGrid = Boolean(state?.guideMirrorLocked) && !Boolean(state?.guideMillerInfluencePlane);
    if (isMirrorGrid) {
      mirrorGuideStates.push(state);
    } else {
      nonMirrorGuideStates.push(state);
    }
  });
  const loadedGuideGrids = [];
  nonMirrorGuideStates.forEach((state) => {
    const grid = addGuideGridFromState(state);
    loadedGuideGrids.push(grid || null);
  });
  const keyToGrid = buildExistingGuideGridKeyMap();
  nonMirrorGuideStates.forEach((state, idx) => {
    const key = typeof state?.saveKey === 'string' ? state.saveKey : `g${idx}`;
    const grid = loadedGuideGrids[idx] || null;
    if (key && grid) {
      keyToGrid.set(key, grid);
    }
  });
  guideAddGrids.forEach((grid) => {
    const key = typeof grid?.userData?.saveKey === 'string' ? grid.userData.saveKey : null;
    if (key && !keyToGrid.has(key)) {
      keyToGrid.set(key, grid);
    }
  });
  rebuildMirrorFromStatesRuntime({
    mirrorStates: mirrorGuideStates,
    maxPasses: 6,
    tryCreateMirrorFromState: (state) => createGuideMirrorGridFromStateLink(state, keyToGrid),
  });
  rebuildMirrorStateOnLoad(keyToGrid, 4);

  const standaloneGroupState = payloadMode === 'group_only_with_guides'
    ? hydrateStandaloneStructureGroupPayload(payload)
    : null;
  const groupedSteelFrameState = standaloneGroupState
    ? standaloneGroupState.steelFrame
    : filterGroupedSteelFrameState(payload?.steelFrame);
  const groupedDecorationStates = standaloneGroupState
    ? standaloneGroupState.decorations
    : filterGroupedDecorationStates(payload?.decorations);
  const mapped = remapStructureGroupIdsForAppend(groupedSteelFrameState, groupedDecorationStates);
  const steelFrameState = mapped.steelFrameState;
  const decorationStates = mapped.decorationStates;
  const reservedGroupIds = new Set(collectStructureGroupIds());
  (mapped.remappedEntries || []).forEach((entry) => {
    const id = String(entry?.remappedGroupId || '').trim();
    if (id) { reservedGroupIds.add(id); }
  });
  const remapSourceIdMap = new Map((mapped.remappedEntries || []).map((entry) => [String(entry?.sourceGroupId || ''), String(entry?.remappedGroupId || '')]));
  const copiedStructureGroups = copiedStructureGroupsRaw.map((entry) => {
    const sourceId = String(entry?.sourceGroupId || '').trim();
    const mappedId = remapSourceIdMap.get(sourceId) || sourceId;
    const requestedGroupId = String(entry?.groupId || '').trim();
    let groupId = requestedGroupId;
    if (groupId) {
      if (!reservedGroupIds.has(groupId)) {
        reservedGroupIds.add(groupId);
      } else {
        let n = 2;
        let candidate = `${groupId}__${n}`;
        while (reservedGroupIds.has(candidate)) {
          n += 1;
          candidate = `${groupId}__${n}`;
        }
        groupId = candidate;
        reservedGroupIds.add(groupId);
      }
    }
    return {
      ...entry,
      sourceGroupId: mappedId,
      groupId: groupId || null,
    };
  });
  const appendSegmentCount = Array.isArray(steelFrameState?.segments) ? steelFrameState.segments.length : 0;
  const appendDecorationCount = decorationStates.length;
  const appendCopiedGroupCount = copiedStructureGroups.length;
  if (appendSegmentCount < 1 && appendDecorationCount < 1 && appendCopiedGroupCount < 1) {
    throw new Error('追加対象のグループ付き構造物が見つかりませんでした。');
  }
  if (appendSegmentCount > 0) {
    restoreSteelFrameState(steelFrameState, keyToGrid);
  }
  if (appendDecorationCount > 0) {
    restoreDecorationsState(decorationStates, keyToGrid);
  }
  if (standaloneGroupState?.rotation && mapped.remappedEntries?.length === 1) {
    const targetGroupId = String(mapped.remappedEntries[0]?.remappedGroupId || '').trim();
    if (targetGroupId) {
      setSavedRotationForStructureGroup(targetGroupId, standaloneGroupState.rotation);
    }
  }
  const restoredCopiedObjectCount = restoreCopiedStructureGroupsFromSave(copiedStructureGroups);
  registerStructureGroupSourceMappings(mapped.remappedEntries, sourceTag);
  syncStructureGroupSequenceFromExisting();
  setRailConstructionGroupOptions();
  updateGroupModePanelUI();
  refreshSteelFrameMirrorPreviews();
  return {
    guideCount: loadedGuideGrids.filter(Boolean).length,
    segmentCount: appendSegmentCount,
    decorationCount: appendDecorationCount,
    copiedGroupCount: appendCopiedGroupCount,
    copiedGroupRestoredObjectCount: Number(restoredCopiedObjectCount) || 0,
    remappedGroupCount: mapped.remappedCount || 0,
  };
}

async function fetchStructureGroupFileListFromFolder(folderUrl = STRUCTURE_GROUP_FOLDER_URL) {
  const toAbsolute = (entry) => {
    try {
      return new URL(entry, location.href).href;
    } catch (_err) {
      return '';
    }
  };
  const normalizeFileList = (rawFiles) => {
    const valid = Array.isArray(rawFiles) ? rawFiles : [];
    const out = [];
    const seen = new Set();
    valid.forEach((file) => {
      const raw = String(file || '').trim();
      if (!raw) { return; }
      const abs = toAbsolute(raw.includes('/') ? raw : `${folderUrl}${raw}`);
      if (!abs) { return; }
      const pathNoQuery = abs.split('?')[0];
      if (!/\.(json|msgpack|mpk)$/i.test(pathNoQuery)) { return; }
      if (seen.has(abs)) { return; }
      seen.add(abs);
      out.push(abs);
    });
    return out;
  };

  try {
    const indexUrl = `${folderUrl}index.json`;
    const response = await fetch(indexUrl, { cache: 'no-store' });
    if (response.ok) {
      const payload = await response.json();
      const files = Array.isArray(payload)
        ? payload
        : Array.isArray(payload?.files)
          ? payload.files
          : [];
      const list = normalizeFileList(files);
      if (list.length > 0) {
        return list;
      }
    }
  } catch (_err) {
    // フォールバックへ。
  }

  try {
    const response = await fetch(folderUrl, { cache: 'no-store' });
    if (!response.ok) { return []; }
    const html = await response.text();
    const links = [];
    const re = /href=["']([^"']+)["']/gi;
    let match = re.exec(html);
    while (match) {
      links.push(match[1]);
      match = re.exec(html);
    }
    return normalizeFileList(links);
  } catch (_err) {
    return [];
  }
}

async function autoLoadStructureGroupsFromFolder() {
  if (structureGroupFolderAutoLoaded) { return; }
  structureGroupFolderAutoLoaded = true;
  const files = await fetchStructureGroupFileListFromFolder(STRUCTURE_GROUP_FOLDER_URL);
  console.info('[structure_group] discovered files', {
    count: Array.isArray(files) ? files.length : 0,
    files,
  });
  if (!Array.isArray(files) || files.length < 1) {
    return;
  }
  const sourceRows = [];
  for (let i = 0; i < files.length; i += 1) {
    const url = files[i];
    try {
      const payload = await readMapDataPayloadFromUrl(url);
      const pathNoQuery = String(url || '').split('?')[0];
      const fileName = decodeURIComponent(pathNoQuery.split('/').pop() || '').trim();
      const sourceTag = fileName
        ? fileName.replace(/\.(json|msgpack|mpk)$/i, '')
        : `structure_group_${i + 1}`;
      const mode = String(payload?.meta?.mode || '').trim();
      const hasCopiedRefs = Array.isArray(payload?.copiedStructureGroups) && payload.copiedStructureGroups.length > 0;
      const isCopyReference = mode === 'group_copy_reference' || hasCopiedRefs;
      sourceRows.push({
        url,
        payload,
        sourceTag,
        isCopyReference,
      });
    } catch (err) {
      console.warn('[structure_group] preload failed', { url, err });
    }
  }
  console.info('[structure_group] preload rows', sourceRows.map((row) => ({
    sourceTag: row.sourceTag,
    isCopyReference: row.isCopyReference,
    url: row.url,
  })));
  const hasMini42 = sourceRows.some((row) => String(row?.sourceTag || '').trim() === 'st_mini_4_2');
  if (!hasMini42) {
    console.warn('[structure_group] missing sourceTag in preload rows: st_mini_4_2', {
      sourceTags: sourceRows.map((row) => row.sourceTag),
    });
  }
  await applyStructureGroupSourceRows(sourceRows, {
    logLabel: '[structure_group]',
    updateStatus: true,
  });
}

async function applyStructureGroupSourceRows(sourceRows, { logLabel = '[structure_group]', updateStatus = false } = {}) {
  const rows = Array.isArray(sourceRows) ? sourceRows : [];
  console.info(`${logLabel} begin`, { rowCount: rows.length });
  if (rows.length < 1) {
    return {
      loadedFiles: 0,
      totalSegments: 0,
      totalDecorations: 0,
      remappedGroups: 0,
    };
  }
  // 元グループを先に復元し、その後でコピー参照を復元する。
  const baseRows = rows.filter((row) => !row.isCopyReference);
  const copyRows = rows.filter((row) => row.isCopyReference);
  let loadedFiles = 0;
  let totalSegments = 0;
  let totalDecorations = 0;
  let remappedGroups = 0;
  for (let i = 0; i < baseRows.length; i += 1) {
    const row = baseRows[i];
    try {
      console.info(`${logLabel} base row start`, { index: i, url: row.url, sourceTag: row.sourceTag });
      const result = appendCreateModeGroupsPayload(row.payload, { sourceTag: row.sourceTag });
      loadedFiles += 1;
      totalSegments += Number(result?.segmentCount) || 0;
      totalDecorations += Number(result?.decorationCount) || 0;
      remappedGroups += Number(result?.remappedGroupCount) || 0;
      console.info(`${logLabel} base row done`, {
        index: i,
        url: row.url,
        sourceTag: row.sourceTag,
        segmentCount: Number(result?.segmentCount) || 0,
        decorationCount: Number(result?.decorationCount) || 0,
        remappedGroupCount: Number(result?.remappedGroupCount) || 0,
      });
    } catch (err) {
      console.error(`${logLabel} load failed`, {
        url: row.url,
        sourceTag: row.sourceTag,
        err,
        errMessage: err?.message || String(err),
        payloadMeta: row?.payload?.meta || null,
        steelPointCount: Array.isArray(row?.payload?.steelFrame?.points) ? row.payload.steelFrame.points.length : -1,
        steelSegmentCount: Array.isArray(row?.payload?.steelFrame?.segments) ? row.payload.steelFrame.segments.length : -1,
        decorationCount: Array.isArray(row?.payload?.decorations) ? row.payload.decorations.length : -1,
        copiedGroupCount: Array.isArray(row?.payload?.copiedStructureGroups) ? row.payload.copiedStructureGroups.length : -1,
      });
    }
  }
  // copiedStructureGroups の参照先が別ファイルにある場合に備えて、
  // 依存が揃うまで複数パスで再試行する。
  const pendingCopyRows = copyRows.slice();
  let pass = 0;
  while (pendingCopyRows.length > 0 && pass <= copyRows.length) {
    pass += 1;
    let progressed = false;
    const retryRows = [];
    for (let i = 0; i < pendingCopyRows.length; i += 1) {
      const row = pendingCopyRows[i];
      try {
        const result = appendCreateModeGroupsPayload(row.payload, { sourceTag: row.sourceTag });
        const copiedCount = Number(result?.copiedGroupCount) || 0;
        const copiedRestoredCount = Number(result?.copiedGroupRestoredObjectCount) || 0;
        if (copiedCount < 1 || copiedRestoredCount > 0) {
          loadedFiles += 1;
          totalSegments += Number(result?.segmentCount) || 0;
          totalDecorations += Number(result?.decorationCount) || 0;
          remappedGroups += Number(result?.remappedGroupCount) || 0;
          progressed = true;
        } else {
          retryRows.push(row);
          console.info(`${logLabel} retry copy reference`, {
            sourceTag: row.sourceTag,
            url: row.url,
            copiedCount,
            copiedRestoredCount,
          });
        }
      } catch (err) {
        console.error(`${logLabel} load failed`, {
          url: row.url,
          sourceTag: row.sourceTag,
          err,
          errMessage: err?.message || String(err),
          payloadMeta: row?.payload?.meta || null,
        });
      }
    }
    if (!progressed) {
      pendingCopyRows.splice(0, pendingCopyRows.length, ...retryRows);
      break;
    }
    pendingCopyRows.splice(0, pendingCopyRows.length, ...retryRows);
  }
  if (pendingCopyRows.length > 0) {
    console.warn(`${logLabel} copy references pending after retry`, pendingCopyRows.map((row) => ({
      sourceTag: row.sourceTag,
      url: row.url,
    })));
    pendingCopyRows.forEach((row) => {
      console.warn(`${logLabel} copy reference unresolved`, { url: row.url, sourceTag: row.sourceTag });
    });
  }
  if (updateStatus && loadedFiles > 0) {
    const statusText = `structure_group 自動読込: ${loadedFiles} files / segment ${totalSegments} / decoration ${totalDecorations} / group再採番 ${remappedGroups}`;
    setMapLoadStatusText(statusText);
    if (railConstructionStatus) { railConstructionStatus.textContent = statusText; }
  }
  console.info(`${logLabel} done`, {
    loadedFiles,
    totalSegments,
    totalDecorations,
    remappedGroups,
    pendingCopyRows: pendingCopyRows.length,
  });
  return {
    loadedFiles,
    totalSegments,
    totalDecorations,
    remappedGroups,
  };
}

