function isBaseGuideGridMoveModeActive() {
  return editObject === 'STEEL_FRAME'
    && objectEditMode === 'MOVE_EXISTING'
    && Array.isArray(targetObjects)
    && targetObjects.includes(addPointGridHandle)
    && movePlaneMode !== 'change_angle';
}

function isGuideGridMoveModeActive() {
  return editObject === 'STEEL_FRAME'
    && objectEditMode === 'MOVE_EXISTING'
    && movePlaneMode !== 'change_angle'
    && (move_direction_y === true || move_direction_y === false);
}

function resetChoiceObjectColor(mesh) {
  if (!mesh) { return; }
  const setMeshColorSafe = (obj, colorHex) => {
    if (!obj) { return false; }
    let painted = false;
    const paintMaterial = (mat) => {
      if (mat?.color?.set) {
        mat.color.set(colorHex);
        painted = true;
      }
    };
    if (Array.isArray(obj.material)) {
      obj.material.forEach((mat) => paintMaterial(mat));
    } else {
      paintMaterial(obj.material);
    }
    obj.traverse?.((node) => {
      if (node === obj) { return; }
      if (Array.isArray(node.material)) {
        node.material.forEach((mat) => paintMaterial(mat));
      } else {
        paintMaterial(node.material);
      }
    });
    return painted;
  };
  const resolvedStructureTarget = resolveCopySelectableFromHit(mesh) || mesh;
  if (copyModeActive && copySelectedObjects.has(resolvedStructureTarget)) {
    setCopyObjectVisual(resolvedStructureTarget, true);
    return;
  }
  if (styleModeActive && styleSelectedObjects.has(resolvedStructureTarget)) {
    setCopyObjectVisual(resolvedStructureTarget, true);
    return;
  }
  if (groupModeActive && groupSelectedObjects.has(resolvedStructureTarget)) {
    setCopyObjectVisual(resolvedStructureTarget, true);
    return;
  }
  if (deleteModeActive && deleteSelectedObjects.has(resolvedStructureTarget)) {
    setCopyObjectVisual(resolvedStructureTarget, true);
    return;
  }
  if (isMovePointReferenceSource(resolvedStructureTarget)) {
    setMeshColorSafe(resolvedStructureTarget, MOVE_POINT_REF_HIGHLIGHT);
    return;
  }
  if (resolvedStructureTarget?.userData?.decorationType) {
    if (resolvedStructureTarget?.material?.color) {
      resolvedStructureTarget.material.color.set(resolvedStructureTarget?.userData?.baseColor || 0x1f2228);
    }
    return;
  }
  if (mesh?.userData?.differenceSpacePlane) {
    setDifferencePlaneVisual(mesh, mesh === differenceSelectedPlane);
    return;
  }
  if (mesh?.userData?.differenceControlPoint) {
    if (isDifferenceControlPointSelected(mesh)) {
      setDifferenceControlPointVisual(mesh, 0x7be6ff);
    } else {
      setDifferenceControlPointVisual(mesh);
    }
    return;
  }
  if (resolvedStructureTarget?.userData?.steelFrameCopiedObject) {
    setMeshColorSafe(resolvedStructureTarget, getSteelSegmentDefaultColor(resolvedStructureTarget));
    return;
  }
  const isConstructionObject = Boolean(
    resolvedStructureTarget?.name === 'SteelFrameSegment'
    || resolvedStructureTarget?.userData?.decorationType
    || String(resolvedStructureTarget?.userData?.railPlacementGroupId || '').trim()
    || String(resolvedStructureTarget?.userData?.structureGroupId || '').trim()
  );
  if (isConstructionObject && !resolvedStructureTarget?.userData?.steelFramePoint) {
    setCopyObjectVisual(resolvedStructureTarget, false);
    return;
  }
  if (editObject === 'STEEL_FRAME' && steelFrameMode?.isSelectedPoint && steelFrameMode.isSelectedPoint(mesh)) {
    // グループ所属は水色に戻す
    if (mesh?.material?.color) {
      mesh.material.color.set(0x7be6ff);
    }
    return;
  }
  if (mesh?.userData?.steelFramePoint && mesh?.userData?.steelFrameCopied) {
    setMeshColorSafe(mesh, 0xffd400);
    return;
  }
  if (editObject === 'STEEL_FRAME' && objectEditMode === 'CONSTRUCT') {
    steelFrameMode.restorePointColor(mesh);
    return;
  }
  if (mesh === addPointGridHandle) {
    setMeshColorSafe(mesh, 0xff0000);
    setAddPointGuideGridColor(0xff0000);
    return;
  }
  if (guideAddGrids.includes(mesh)) {
    const baseColor = Number(mesh?.userData?.guideGridColor) || GUIDE_ADD_GRID_COLOR;
    setGuideAddGridColor(mesh, baseColor);
    return;
  }
  if (mesh?.userData?.railStructureHandle && mesh?.userData?.railStructurePickHandle) {
    setMeshColorSafe(mesh, 0x00a8ff);
    return;
  }
  if (objectEditMode === 'CONSTRUCT' && !pick_vertexs.includes(mesh.id)) {
    setMeshColorSafe(mesh, 0xff0000);
    return;
  }
  setMeshColorSafe(mesh, 0xff0000);
}

// 毎フレーム時に実行されるループイベントです
async function search_point() {
  
  if (!search_object){return}

  if (editObject === 'RAIL'
    && (objectEditMode === 'MOVE_EXISTING' || objectEditMode === ROTATE_MODE)) {
    await sleep(80);
    const picked = pickRailMoveTargetFromPointer({ allowRailPoint: objectEditMode === 'MOVE_EXISTING' });
    if (picked && choice_object !== picked && !dragging && !rotateDragging) {
      if (choice_object && choice_object !== false && choice_object?.material?.color?.set) {
        resetChoiceObjectColor(choice_object);
      }
      choice_object = picked;
      if (choice_object?.material?.color?.set) {
        choice_object.material.color.set(0x00ff00);
      }
      if (objectEditMode === ROTATE_MODE) {
        updateRotateGizmo();
      }
    }
    updateRailSelectionStatus();
    renderer.render(scene, camera);
    await search_point();
    return;
  }

  // 画面上の光線とぶつかったオブジェクトを得る
  const intersects = getIntersectObjects();
  
  await sleep(80);

  if (intersects.length > 0) {
    const guideHit = intersects.find(hit => hit?.object?.userData?.isGuideRail);
    if (!addPointGridActive || objectEditMode === 'MOVE_EXISTING') {
      guideRailHover = null;
      setGuideHoverPin(null);
    } else if (guideHit?.object?.userData?.isGuideRail && guideHit.point) {
      const curve = guideHit.object.userData.guideCurve;
      const nearest = curve ? getNearestPointOnCurve(curve, guideHit.point) : null;
      guideRailHover = nearest ? { curve, point: nearest } : null;
      if (guideRailHover) {
        GuideGrid.visible = true;
        GuideGrid.position.copy(guideRailHover.point);
        GuideGrid.quaternion.identity();
        GuideGrid.material.color.set(0x88aa88);
        setGuideHoverPin(guideRailHover.point);
      }
    } else {
      guideRailHover = null;
      setGuideHoverPin(null);
    }
    // console.log('hit')
    // console.log(intersects.length)
    const firstHit = intersects[0];
    const hitObjectRaw = firstHit.object;
    const movePointHitObject = resolveMovePointPreferredHitObject(intersects)
      || resolveMovePointTargetFromIntersect(firstHit);
    const hitObject = movePointHitObject || resolveSelectableHitObject(hitObjectRaw);
    if (choice_object != hitObject){
      if (choice_object !== false){ 
        // 残像防止
        console.log('green')
        resetChoiceObjectColor(choice_object);

        GuideLine.visible = false
      }

      // 物体の取得
      choice_object = hitObject
      if (choice_object?.material?.color) {
        choice_object.material.color.set(0x00ff00)
      }
      if (choice_object === addPointGridHandle) {
        setAddPointGuideGridColor(0x00ff00);
      }

      console.log('color set')
      console.log(choice_object)

      if (move_direction_y){
        GuideLine.position.copy(choice_object.position)
        GuideLine.quaternion.identity()
        GuideLine.visible = true
      } else if (pointRotateModeActive) {
        showPointRotationGuideLine(choice_object);

      } else {
        if (movePlaneMode !== 'change_angle') {
          GuideGrid.visible = true
        }
        if (targetObjects.includes(addPointGridHandle)) {
          setAddPointGuideGridColor(0x88aa88)
          if (movePlaneMode !== 'change_angle') {
            syncGuideGridFromObject(choice_object)
            GuideGrid.material.color.set(0x88aa88)
          }
        } else {
          if (movePlaneMode !== 'change_angle') {
            syncGuideGridFromObject(choice_object)
            GuideGrid.material.color.set(0x88aa88)
          }
        }
        // visibility controlled by UIevent
      }
    }

  } else {
    // console.log('not hit')
    if (choice_object !== false){
      resetChoiceObjectColor(choice_object);
    }

    choice_object = false;
    guideRailHover = null;
    setGuideHoverPin(null);
    // dragging = false;
    GuideLine.visible = false
    GuideGrid.visible = false
    GuideGrid.quaternion.identity();
  }  

  // レンダリング
  updateRailSelectionStatus();
  renderer.render(scene, camera);
  await search_point();
}

